SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The three essential elements of a communication system are:", "explanation": "Every communication system consists of three fundamental blocks: (1) Transmitter — converts the message signal into a form suitable for transmission, (2) Channel — the physical medium through which the signal travels (wire, free space, optical fibre), and (3) Receiver — extracts the original message from the received signal.", "correct_answer": "A", "concept_tags": ["communication-elements", "transmitter", "receiver", "channel"], "payload": {"question_id": "cuet-phy-comm-01", "subtopic": "basic blocks", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Transmitter, Channel, Receiver", "is_correct": true}, {"key": "B", "text": "Oscillator, Amplifier, Antenna", "is_correct": false}, {"key": "C", "text": "Modulator, Demodulator, Amplifier", "is_correct": false}, {"key": "D", "text": "Encoder, Decoder, Repeater", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Oscillator, amplifier and antenna are components within a transmitter, not the three main blocks of the system.", "misconception": "Confusing sub-components with main elements"}, {"option_key": "C", "hint": "Modulator and demodulator are parts of the transmitter and receiver respectively, not the three fundamental elements.", "misconception": "Listing processes instead of system blocks"}, {"option_key": "D", "hint": "Encoder and decoder are used in digital communication. Repeater is an intermediate device. These are not the three fundamental elements.", "misconception": "Mixing digital communication terms with basic structure"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A transducer in a communication system is a device that:", "explanation": "A transducer converts one form of energy into another. In communication, the transmitting transducer converts the message (sound, image, data) into an electrical signal. For example, a microphone converts sound energy into electrical energy, and a camera converts light into electrical signals.", "correct_answer": "B", "concept_tags": ["transducer", "energy-conversion", "input-device"], "payload": {"question_id": "cuet-phy-comm-02", "subtopic": "transducer", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Amplifies the signal", "is_correct": false}, {"key": "B", "text": "Converts one form of energy into another", "is_correct": true}, {"key": "C", "text": "Filters unwanted frequencies", "is_correct": false}, {"key": "D", "text": "Modulates the carrier wave", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Signal amplification is done by an amplifier, not a transducer.", "misconception": "Confusing transducer with amplifier"}, {"option_key": "C", "hint": "Filtering unwanted frequencies is done by a band-pass filter, not a transducer.", "misconception": "Confusing transducer with filter"}, {"option_key": "D", "hint": "Modulation is done by a modulator circuit. A transducer only converts the physical signal to electrical form.", "misconception": "Confusing transducer with modulator"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The process of retrieving the original message signal from the modulated carrier wave at the receiver is called:", "explanation": "Demodulation (or detection) is the process of extracting the original message signal from the modulated carrier wave. It is the reverse of modulation and is performed at the receiver end. For AM signals, an envelope detector is commonly used for demodulation.", "correct_answer": "C", "concept_tags": ["demodulation", "detection", "receiver"], "payload": {"question_id": "cuet-phy-comm-03", "subtopic": "demodulation", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Modulation", "is_correct": false}, {"key": "B", "text": "Amplification", "is_correct": false}, {"key": "C", "text": "Demodulation", "is_correct": true}, {"key": "D", "text": "Transmission", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Modulation is the opposite process — it combines the message with a carrier at the transmitter, not recovery at receiver.", "misconception": "Confusing modulation with demodulation"}, {"option_key": "B", "hint": "Amplification increases signal strength but does not extract the original message from the carrier.", "misconception": "Confusing signal strengthening with message recovery"}, {"option_key": "D", "hint": "Transmission is sending the signal through the channel, not recovering the message.", "misconception": "Confusing the sending process with the receiving process"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-bandwidth", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The bandwidth of a speech signal for telephonic communication is approximately:", "explanation": "For telephone-quality speech, the frequency range is approximately 300 Hz to 3400 Hz, giving a bandwidth of about 3100 Hz ≈ 3 kHz. Music requires higher bandwidth (~20 kHz), and video requires even more (~4.2 MHz for analog TV).", "correct_answer": "A", "concept_tags": ["bandwidth", "speech-signal", "frequency-range"], "payload": {"question_id": "cuet-phy-comm-04", "subtopic": "signal bandwidth", "topic_name": "Bandwidth of Signals and Channels", "bloom_level": "remember", "options": [{"key": "A", "text": "3 kHz", "is_correct": true}, {"key": "B", "text": "20 kHz", "is_correct": false}, {"key": "C", "text": "4.2 MHz", "is_correct": false}, {"key": "D", "text": "300 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "20 kHz is the bandwidth of high-fidelity music signals (20 Hz to 20 kHz), not telephonic speech.", "misconception": "Confusing speech bandwidth with audio bandwidth"}, {"option_key": "C", "hint": "4.2 MHz is the bandwidth of an analog video/TV signal, far more than what speech requires.", "misconception": "Confusing speech with video bandwidth"}, {"option_key": "D", "hint": "300 MHz is a carrier frequency range, not a message signal bandwidth.", "misconception": "Confusing carrier frequency with signal bandwidth"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-bandwidth", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If an audio signal of 10 kHz is used to modulate a carrier of 1 MHz, the bandwidth of the AM signal is:", "explanation": "In amplitude modulation, the modulated signal contains the carrier frequency fc and two sidebands: (fc + fm) and (fc − fm). The bandwidth = 2fm = 2 × 10 kHz = 20 kHz. The AM signal occupies from (1000 − 10) kHz to (1000 + 10) kHz = 990 kHz to 1010 kHz.", "correct_answer": "B", "concept_tags": ["AM-bandwidth", "sidebands", "twice-modulating-frequency"], "payload": {"question_id": "cuet-phy-comm-05", "subtopic": "AM signal bandwidth", "topic_name": "Bandwidth of Signals and Channels", "bloom_level": "apply", "options": [{"key": "A", "text": "10 kHz", "is_correct": false}, {"key": "B", "text": "20 kHz", "is_correct": true}, {"key": "C", "text": "1 MHz", "is_correct": false}, {"key": "D", "text": "1.01 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 kHz is the modulating frequency fm. Bandwidth of AM = 2fm because there are two sidebands.", "misconception": "Forgetting that AM has two sidebands (upper and lower)"}, {"option_key": "C", "hint": "1 MHz is the carrier frequency, not the bandwidth. Bandwidth is the range of frequencies occupied by the modulated signal.", "misconception": "Confusing carrier frequency with bandwidth"}, {"option_key": "D", "hint": "1.01 MHz is the upper sideband frequency (fc + fm), not the bandwidth.", "misconception": "Confusing sideband frequency with bandwidth"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ground wave propagation is suitable for frequencies:", "explanation": "Ground wave propagation works for frequencies below about 2 MHz. The radio waves follow the curvature of the Earth along its surface. At higher frequencies, the ground absorbs more energy, making ground wave propagation ineffective. AM radio broadcasting (530–1710 kHz) uses ground wave propagation.", "correct_answer": "A", "concept_tags": ["ground-wave", "low-frequency", "propagation-mode"], "payload": {"question_id": "cuet-phy-comm-06", "subtopic": "ground wave propagation", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "Up to 2 MHz", "is_correct": true}, {"key": "B", "text": "2 MHz to 30 MHz", "is_correct": false}, {"key": "C", "text": "30 MHz to 300 MHz", "is_correct": false}, {"key": "D", "text": "Above 300 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "2–30 MHz (short wave) is the range for sky wave (ionospheric) propagation, not ground wave.", "misconception": "Confusing ground wave with sky wave frequency range"}, {"option_key": "C", "hint": "30–300 MHz (VHF) uses space wave (line-of-sight) propagation, not ground wave.", "misconception": "Confusing ground wave with space wave"}, {"option_key": "D", "hint": "Above 300 MHz (UHF and beyond) uses space wave/satellite communication. Ground absorption is too high.", "misconception": "Thinking higher frequency means better ground propagation"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Sky wave propagation is used for long-distance communication using the reflection of radio waves from the:", "explanation": "Sky wave propagation relies on the ionosphere — a layer of the atmosphere (80–400 km altitude) containing ionised gases. The ionosphere reflects radio waves in the frequency range 2–30 MHz back to Earth. This allows communication over thousands of kilometres by successive reflections between the ionosphere and Earth''s surface.", "correct_answer": "B", "concept_tags": ["sky-wave", "ionosphere", "reflection"], "payload": {"question_id": "cuet-phy-comm-07", "subtopic": "sky wave propagation", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "Troposphere", "is_correct": false}, {"key": "B", "text": "Ionosphere", "is_correct": true}, {"key": "C", "text": "Stratosphere", "is_correct": false}, {"key": "D", "text": "Ozone layer", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The troposphere (0–12 km) causes weather effects on signals but does not reflect radio waves like the ionosphere does.", "misconception": "Confusing troposphere with ionosphere"}, {"option_key": "C", "hint": "The stratosphere (12–50 km) contains the ozone layer but lacks the free electrons needed to reflect radio waves.", "misconception": "Mixing up atmospheric layers"}, {"option_key": "D", "hint": "The ozone layer absorbs UV radiation but does not reflect radio waves. Radio wave reflection needs free electrons.", "misconception": "Confusing UV absorption with radio wave reflection"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum range of a TV transmitting tower of height h above the Earth''s surface is given by d = √(2Rh), where R is the radius of Earth. If the tower height is doubled, the range becomes:", "explanation": "Range d = √(2Rh). If h is doubled: d'' = √(2R × 2h) = √(2 × 2Rh) = √2 × √(2Rh) = √2 × d. So the range increases by a factor of √2, i.e., d'' = √2 d ≈ 1.414d.", "correct_answer": "C", "concept_tags": ["tower-range", "line-of-sight", "height-dependence"], "payload": {"question_id": "cuet-phy-comm-08", "subtopic": "space wave range formula", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "2d", "is_correct": false}, {"key": "B", "text": "4d", "is_correct": false}, {"key": "C", "text": "√2 d", "is_correct": true}, {"key": "D", "text": "d/√2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "d is proportional to √h, not h. Doubling h gives √2 × d, not 2d.", "misconception": "Assuming linear relationship between range and height"}, {"option_key": "B", "hint": "4d would require h to increase 16 times (since d ∝ √h, d'' = 4d requires h'' = 16h).", "misconception": "Squaring instead of taking square root"}, {"option_key": "D", "hint": "d/√2 means the range decreases, which contradicts the fact that a taller tower should have greater range.", "misconception": "Inverting the relationship"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The main reason for modulation in communication is:", "explanation": "Audio signals (20 Hz – 20 kHz) have wavelengths of 15 km to 15,000 km. An antenna needs to be at least λ/4 long to radiate efficiently, which would require impractically large antennas. By modulating onto a high-frequency carrier, the effective wavelength becomes much smaller, allowing practical antenna sizes.", "correct_answer": "D", "concept_tags": ["need-for-modulation", "antenna-size", "practical"], "payload": {"question_id": "cuet-phy-comm-09", "subtopic": "need for modulation", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "understand", "options": [{"key": "A", "text": "To increase the power of the signal", "is_correct": false}, {"key": "B", "text": "To reduce noise in the signal", "is_correct": false}, {"key": "C", "text": "To convert analog to digital", "is_correct": false}, {"key": "D", "text": "To enable transmission using antennas of practical size", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Amplifiers increase power. Modulation shifts the frequency band, it does not increase power.", "misconception": "Confusing modulation with amplification"}, {"option_key": "B", "hint": "While FM has better noise immunity than AM, noise reduction is not the primary reason for modulation.", "misconception": "Confusing a secondary benefit with the main purpose"}, {"option_key": "C", "hint": "Analog-to-digital conversion is digitisation, not modulation. AM and FM are analog modulation techniques.", "misconception": "Confusing modulation with digitisation"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In amplitude modulation, which property of the carrier wave is varied?", "explanation": "In amplitude modulation (AM), the amplitude of the high-frequency carrier wave is varied in accordance with the instantaneous value of the modulating (message) signal. The frequency and phase of the carrier remain constant. In FM, the frequency is varied; in PM, the phase is varied.", "correct_answer": "A", "concept_tags": ["amplitude-modulation", "carrier-amplitude", "AM-definition"], "payload": {"question_id": "cuet-phy-comm-10", "subtopic": "definition of AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "remember", "options": [{"key": "A", "text": "Amplitude", "is_correct": true}, {"key": "B", "text": "Frequency", "is_correct": false}, {"key": "C", "text": "Phase", "is_correct": false}, {"key": "D", "text": "Wavelength and amplitude both", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Varying frequency is frequency modulation (FM), not amplitude modulation.", "misconception": "Confusing AM with FM"}, {"option_key": "C", "hint": "Varying phase is phase modulation (PM), a different technique from AM.", "misconception": "Confusing AM with PM"}, {"option_key": "D", "hint": "In AM, only the amplitude changes. The frequency (and hence wavelength) of the carrier stays constant.", "misconception": "Thinking multiple properties change simultaneously in AM"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The modulation index of an AM wave is 0.6. The ratio of the maximum amplitude to the minimum amplitude of the modulated wave is:", "explanation": "For AM, Amax = Ac(1 + m) and Amin = Ac(1 − m), where m is the modulation index. Ratio = Amax/Amin = (1 + m)/(1 − m) = (1 + 0.6)/(1 − 0.6) = 1.6/0.4 = 4.", "correct_answer": "C", "concept_tags": ["modulation-index", "Amax-Amin", "numerical"], "payload": {"question_id": "cuet-phy-comm-11", "subtopic": "modulation index calculation", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6", "is_correct": false}, {"key": "B", "text": "2.5", "is_correct": false}, {"key": "C", "text": "4", "is_correct": true}, {"key": "D", "text": "0.6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 is (1 + m), the maximum amplitude relative to carrier. The question asks the ratio Amax/Amin.", "misconception": "Calculating Amax/Ac instead of Amax/Amin"}, {"option_key": "B", "hint": "2.5 is 1/Amin = 1/0.4 — not the correct ratio. You need (1+m)/(1−m).", "misconception": "Arithmetic error in ratio calculation"}, {"option_key": "D", "hint": "0.6 is the modulation index itself, not the amplitude ratio.", "misconception": "Restating the given value as the answer"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "For an AM wave, the carrier frequency is 1 MHz and the modulating frequency is 5 kHz. The frequencies of the upper and lower sidebands are:", "explanation": "In AM, the upper sideband (USB) frequency = fc + fm = 1000 + 5 = 1005 kHz, and the lower sideband (LSB) frequency = fc − fm = 1000 − 5 = 995 kHz. The AM spectrum consists of three frequencies: LSB, carrier, and USB.", "correct_answer": "A", "concept_tags": ["sidebands", "USB-LSB", "AM-spectrum"], "payload": {"question_id": "cuet-phy-comm-12", "subtopic": "sideband frequencies", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1005 kHz and 995 kHz", "is_correct": true}, {"key": "B", "text": "1050 kHz and 950 kHz", "is_correct": false}, {"key": "C", "text": "1005 MHz and 995 MHz", "is_correct": false}, {"key": "D", "text": "1500 kHz and 500 kHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1050 and 950 kHz means fm = 50 kHz, not 5 kHz. Check unit conversion: 5 kHz = 5 kHz, not 50 kHz.", "misconception": "Adding an extra zero to the modulating frequency"}, {"option_key": "C", "hint": "The units are wrong — sidebands are in kHz (near 1000 kHz = 1 MHz), not in MHz.", "misconception": "Using wrong units — MHz instead of kHz"}, {"option_key": "D", "hint": "1500 and 500 kHz would mean fm = 500 kHz = 0.5 MHz, not 5 kHz. Massive arithmetic error.", "misconception": "Confusing kHz with MHz in the modulating frequency"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The modulation index of an AM signal is 0.5. The fraction of total power carried by the carrier is:", "explanation": "In AM, total power Pt = Pc(1 + m²/2), where Pc is carrier power. Fraction of power in carrier = Pc/Pt = 1/(1 + m²/2) = 1/(1 + 0.25/2) = 1/(1 + 0.125) = 1/1.125 = 8/9 ≈ 0.889 or 88.9%. This shows that in AM, most power is wasted in the carrier which carries no information.", "correct_answer": "B", "concept_tags": ["AM-power", "carrier-power-fraction", "efficiency"], "payload": {"question_id": "cuet-phy-comm-13", "subtopic": "power in AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1/2", "is_correct": false}, {"key": "B", "text": "8/9", "is_correct": true}, {"key": "C", "text": "4/5", "is_correct": false}, {"key": "D", "text": "2/3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/2 would mean half the power in carrier, which only happens at m = √2 (over-modulation). For m = 0.5, the carrier carries much more.", "misconception": "Guessing without using the formula"}, {"option_key": "C", "hint": "4/5 = 0.8 corresponds to m²/2 = 0.25, i.e., m = √0.5 ≈ 0.707, not 0.5.", "misconception": "Using wrong value for m in the formula"}, {"option_key": "D", "hint": "2/3 = 0.667 corresponds to m²/2 = 0.5, i.e., m = 1. Not 0.5.", "misconception": "Substituting m = 1 instead of m = 0.5"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An audio signal of 3 kHz is amplitude modulated with a carrier of 810 kHz. The frequencies present in the AM wave are:", "explanation": "An AM wave contains three frequency components: the carrier frequency fc = 810 kHz, the upper sideband fc + fm = 810 + 3 = 813 kHz, and the lower sideband fc − fm = 810 − 3 = 807 kHz. These three discrete frequencies make up the AM spectrum.", "correct_answer": "D", "concept_tags": ["AM-frequencies", "three-components", "spectrum"], "payload": {"question_id": "cuet-phy-comm-14", "subtopic": "AM wave frequency components", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "810 kHz only", "is_correct": false}, {"key": "B", "text": "807 kHz and 813 kHz only", "is_correct": false}, {"key": "C", "text": "3 kHz, 810 kHz, and 813 kHz", "is_correct": false}, {"key": "D", "text": "807 kHz, 810 kHz, and 813 kHz", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "810 kHz alone is an unmodulated carrier. Modulation creates additional sideband frequencies.", "misconception": "Thinking modulation doesn''t create new frequencies"}, {"option_key": "B", "hint": "The carrier frequency is always present in AM — it''s the dominant component. You cannot omit it.", "misconception": "Thinking AM suppresses the carrier"}, {"option_key": "C", "hint": "The original modulating frequency (3 kHz) is NOT present in the AM wave. Only fc, fc+fm, and fc−fm appear.", "misconception": "Thinking the baseband signal appears directly in the AM wave"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A TV tower has a height of 100 m. The maximum distance up to which the TV transmission can be received is: (Take R = 6.4 × 10⁶ m)", "explanation": "Using d = √(2Rh) = √(2 × 6.4 × 10⁶ × 100) = √(12.8 × 10⁸) = √(1.28 × 10⁹) = 3.58 × 10⁴ m ≈ 35.8 km.", "correct_answer": "B", "concept_tags": ["tower-range-numerical", "line-of-sight", "space-wave"], "payload": {"question_id": "cuet-phy-comm-15", "subtopic": "range calculation", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "25.3 km", "is_correct": false}, {"key": "B", "text": "35.8 km", "is_correct": true}, {"key": "C", "text": "50.5 km", "is_correct": false}, {"key": "D", "text": "71.6 km", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "25.3 km corresponds to using d = √(Rh) instead of d = √(2Rh) — the factor of 2 is missing.", "misconception": "Forgetting the factor of 2 in the formula"}, {"option_key": "C", "hint": "50.5 km would correspond to h ≈ 200 m. Check: √(2 × 6.4 × 10⁶ × 200) ≈ 50.6 km.", "misconception": "Using h = 200 m instead of 100 m"}, {"option_key": "D", "hint": "71.6 km is 2 × 35.8 km. Range is proportional to √h, not h.", "misconception": "Using d = 2Rh or d = 2√(2Rh)"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-detection", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the process of AM detection, the component that removes the high-frequency carrier from the rectified signal is:", "explanation": "After rectification (using a diode), the signal still contains the high-frequency carrier ripple superimposed on the message signal. A low-pass filter (typically an RC circuit) removes the high-frequency carrier components and passes only the low-frequency message signal (envelope). This process is called envelope detection.", "correct_answer": "B", "concept_tags": ["detection", "envelope-detector", "low-pass-filter"], "payload": {"question_id": "cuet-phy-comm-16", "subtopic": "AM detection circuit", "topic_name": "Detection and Demodulation", "bloom_level": "understand", "options": [{"key": "A", "text": "High-pass filter", "is_correct": false}, {"key": "B", "text": "Low-pass filter", "is_correct": true}, {"key": "C", "text": "Band-pass filter", "is_correct": false}, {"key": "D", "text": "Oscillator", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A high-pass filter would do the opposite — pass the carrier and remove the message signal.", "misconception": "Confusing low-pass and high-pass filter functions"}, {"option_key": "C", "hint": "A band-pass filter passes a specific band. In detection, we need to remove the carrier entirely, which a low-pass filter does.", "misconception": "Confusing the filter used in tuning with detection"}, {"option_key": "D", "hint": "An oscillator generates signals (used in the transmitter for carrier generation), not for filtering.", "misconception": "Confusing signal generation with signal filtering"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum modulation index for distortion-free AM is:", "explanation": "The modulation index m = Am/Ac, where Am is the message amplitude and Ac is the carrier amplitude. For distortion-free AM, m must satisfy 0 ≤ m ≤ 1. When m > 1 (over-modulation), the envelope of the AM wave gets distorted, causing the recovered signal to not faithfully reproduce the original message.", "correct_answer": "C", "concept_tags": ["modulation-index-limit", "over-modulation", "distortion"], "payload": {"question_id": "cuet-phy-comm-17", "subtopic": "modulation index limits", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "remember", "options": [{"key": "A", "text": "0.5", "is_correct": false}, {"key": "B", "text": "0.75", "is_correct": false}, {"key": "C", "text": "1", "is_correct": true}, {"key": "D", "text": "2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "m = 0.5 is within the allowed range but is not the maximum. Higher modulation up to 1 is still distortion-free.", "misconception": "Being overly conservative about the limit"}, {"option_key": "B", "hint": "m = 0.75 is used in practice for safety margin, but theoretically m = 1 is the maximum for distortion-free AM.", "misconception": "Confusing practical recommendation with theoretical limit"}, {"option_key": "D", "hint": "m = 2 means the message amplitude is twice the carrier — this causes severe over-modulation and envelope distortion.", "misconception": "Thinking modulation index can exceed 1 without distortion"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The critical frequency of an ionospheric layer with maximum electron density Nmax is given by fc = 9√(Nmax). If Nmax = 10¹² electrons/m³, the critical frequency is:", "explanation": "fc = 9√(Nmax) = 9√(10¹²) = 9 × 10⁶ Hz = 9 MHz. The critical frequency is the maximum frequency that can be reflected by the ionosphere at vertical incidence. Frequencies above fc pass through the ionosphere and cannot be used for sky wave communication.", "correct_answer": "C", "concept_tags": ["critical-frequency", "electron-density", "ionosphere"], "payload": {"question_id": "cuet-phy-comm-18", "subtopic": "critical frequency of ionosphere", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "9 kHz", "is_correct": false}, {"key": "B", "text": "900 kHz", "is_correct": false}, {"key": "C", "text": "9 MHz", "is_correct": true}, {"key": "D", "text": "90 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "9 kHz = 9 × 10³ Hz. Check: 9√(10¹²) = 9 × 10⁶ Hz = 9 MHz, not 9 kHz.", "misconception": "Error in calculating √(10¹²) — should be 10⁶, not 10³"}, {"option_key": "B", "hint": "900 kHz = 9 × 10⁵ Hz, which would need Nmax = 10¹⁰. For Nmax = 10¹², fc = 9 × 10⁶.", "misconception": "Off by a factor of 10"}, {"option_key": "D", "hint": "90 MHz = 9 × 10⁷ Hz would need Nmax ≈ 10¹⁴, not 10¹². Exponent error.", "misconception": "Adding instead of halving the exponent in square root"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A repeater in a communication system is used to:", "explanation": "A repeater receives the attenuated signal, amplifies it, and retransmits it. It extends the range of communication by compensating for signal loss (attenuation) during transmission over long distances. Repeaters are placed at intervals along the communication channel.", "correct_answer": "B", "concept_tags": ["repeater", "amplification", "range-extension"], "payload": {"question_id": "cuet-phy-comm-19", "subtopic": "repeater", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Convert analog signals to digital", "is_correct": false}, {"key": "B", "text": "Extend the range by amplifying and retransmitting the signal", "is_correct": true}, {"key": "C", "text": "Modulate the carrier wave", "is_correct": false}, {"key": "D", "text": "Reduce noise in the signal", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Analog-to-digital conversion is done by an ADC (analog-to-digital converter), not a repeater.", "misconception": "Confusing repeater with ADC"}, {"option_key": "C", "hint": "Modulation is done at the transmitter. A repeater works on an already modulated signal.", "misconception": "Confusing repeater with modulator"}, {"option_key": "D", "hint": "While digital repeaters can regenerate signals, the primary function is to amplify and retransmit, not noise reduction.", "misconception": "Confusing a secondary benefit with the primary function"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An AM wave is represented as: y = [10 + 6 sin(2π × 1500t)] sin(2π × 10⁵ t). The modulation index and carrier frequency are:", "explanation": "Comparing with the standard form y = Ac[1 + m sin(2πfmt)] sin(2πfct): Ac = 10, mAc = 6, so m = 6/10 = 0.6. The carrier frequency fc = 10⁵ Hz = 100 kHz. The modulating frequency fm = 1500 Hz = 1.5 kHz.", "correct_answer": "A", "concept_tags": ["AM-wave-equation", "extract-parameters", "carrier-frequency"], "payload": {"question_id": "cuet-phy-comm-20", "subtopic": "AM wave equation analysis", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "0.6 and 100 kHz", "is_correct": true}, {"key": "B", "text": "0.6 and 1.5 kHz", "is_correct": false}, {"key": "C", "text": "6 and 100 kHz", "is_correct": false}, {"key": "D", "text": "0.06 and 10⁵ MHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1.5 kHz is the modulating frequency (fm), not the carrier frequency. The carrier is the higher frequency: 10⁵ Hz = 100 kHz.", "misconception": "Confusing modulating frequency with carrier frequency"}, {"option_key": "C", "hint": "m = Am/Ac = 6/10 = 0.6, not 6. The modulation index is a ratio, always ≤ 1 for distortion-free AM.", "misconception": "Using the amplitude directly instead of the ratio"}, {"option_key": "D", "hint": "10⁵ Hz = 100 kHz = 0.1 MHz, not 10⁵ MHz. Also m = 0.6, not 0.06.", "misconception": "Unit confusion between Hz and MHz"}]}}]'::jsonb, 'deploy-2026-03-05-b01');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The total power of an AM wave is 600 W. If the modulation index is 0.75, the power of the carrier wave is:", "explanation": "Total AM power: Pt = Pc(1 + m²/2). So Pc = Pt/(1 + m²/2) = 600/(1 + 0.75²/2) = 600/(1 + 0.5625/2) = 600/(1 + 0.28125) = 600/1.28125 ≈ 468.3 W.", "correct_answer": "B", "concept_tags": ["AM-power", "carrier-power", "numerical"], "payload": {"question_id": "cuet-phy-comm-21", "subtopic": "power calculation in AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "400 W", "is_correct": false}, {"key": "B", "text": "468.3 W", "is_correct": true}, {"key": "C", "text": "512 W", "is_correct": false}, {"key": "D", "text": "300 W", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "400 W corresponds to Pt/(1 + m²) instead of Pt/(1 + m²/2). The denominator has m²/2, not m².", "misconception": "Using wrong formula: forgetting the ½ factor"}, {"option_key": "C", "hint": "Check: 600/1.28125 ≈ 468.3, not 512. Recompute the denominator carefully.", "misconception": "Arithmetic error in division"}, {"option_key": "D", "hint": "300 W is half the total power, implying m²/2 = 1 i.e. m = √2. But m = 0.75.", "misconception": "Simply halving the total power"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Satellite communication uses which mode of wave propagation?", "explanation": "Satellite communication uses space wave (line-of-sight) propagation. Signals are transmitted from Earth to a satellite at frequencies above 30 MHz (typically GHz range), which pass straight through the ionosphere without reflection. The satellite receives, amplifies, and retransmits the signal back to a different location on Earth.", "correct_answer": "C", "concept_tags": ["satellite", "space-wave", "line-of-sight"], "payload": {"question_id": "cuet-phy-comm-22", "subtopic": "satellite communication", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "Ground wave propagation", "is_correct": false}, {"key": "B", "text": "Sky wave propagation", "is_correct": false}, {"key": "C", "text": "Space wave propagation", "is_correct": true}, {"key": "D", "text": "Surface wave propagation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Ground wave follows Earth''s surface and works only below 2 MHz. Satellite uses GHz frequencies.", "misconception": "Confusing ground wave with space wave"}, {"option_key": "B", "hint": "Sky wave uses ionospheric reflection (2–30 MHz). Satellite frequencies are much higher and pass through the ionosphere.", "misconception": "Thinking satellite signals bounce off the ionosphere"}, {"option_key": "D", "hint": "Surface wave is another name for ground wave propagation. Not used for satellite communication.", "misconception": "Using alternate terminology for ground wave"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two towers of heights 50 m and 72 m are separated by 40 km. What is the maximum distance between them for line-of-sight communication? (R = 6.4 × 10⁶ m)", "explanation": "For two towers, maximum LOS distance = √(2Rh₁) + √(2Rh₂). d₁ = √(2 × 6.4 × 10⁶ × 50) = √(6.4 × 10⁸) = 25.3 km. d₂ = √(2 × 6.4 × 10⁶ × 72) = √(9.216 × 10⁸) = 30.36 km. Total = 25.3 + 30.36 = 55.66 km. Since 40 km < 55.66 km, they CAN communicate. The maximum distance is 55.66 km.", "correct_answer": "C", "concept_tags": ["two-tower-range", "LOS-distance", "numerical"], "payload": {"question_id": "cuet-phy-comm-23", "subtopic": "two-tower line-of-sight", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "25.3 km", "is_correct": false}, {"key": "B", "text": "30.4 km", "is_correct": false}, {"key": "C", "text": "55.7 km", "is_correct": true}, {"key": "D", "text": "40 km", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "25.3 km is the range of tower 1 alone (h = 50 m). For two towers, add both individual ranges.", "misconception": "Using only one tower''s range"}, {"option_key": "B", "hint": "30.4 km is the range of tower 2 alone (h = 72 m). The total LOS distance is d₁ + d₂.", "misconception": "Using only the taller tower''s range"}, {"option_key": "D", "hint": "40 km is the actual separation given, not the maximum possible LOS distance.", "misconception": "Confusing actual separation with maximum range"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-detection", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The first step in AM detection (demodulation) is:", "explanation": "AM detection involves: (1) Rectification — a diode removes one half of the AM wave (since the envelope has symmetric positive and negative halves), leaving a pulsating signal. (2) Filtering — a low-pass (RC) filter removes the carrier frequency ripple, leaving only the message signal envelope.", "correct_answer": "A", "concept_tags": ["AM-detection", "rectification", "diode"], "payload": {"question_id": "cuet-phy-comm-24", "subtopic": "AM detection steps", "topic_name": "Detection and Demodulation", "bloom_level": "understand", "options": [{"key": "A", "text": "Rectification using a diode", "is_correct": true}, {"key": "B", "text": "Amplification using a transistor", "is_correct": false}, {"key": "C", "text": "Filtering using a band-pass filter", "is_correct": false}, {"key": "D", "text": "Mixing with a local oscillator", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Amplification may be needed, but the essential first step of detection is rectification to extract the envelope.", "misconception": "Confusing amplification with detection"}, {"option_key": "C", "hint": "Band-pass filtering is used in the tuning stage (before detection) to select the desired station, not in detection itself.", "misconception": "Confusing station selection with signal detection"}, {"option_key": "D", "hint": "Mixing with a local oscillator is used in superheterodyne receivers, which is an advanced technique, not basic AM envelope detection.", "misconception": "Confusing simple detection with heterodyne detection"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Long-distance radio communication is possible due to reflection of radio waves by the ionosphere.\nReason (R): The ionosphere contains a high density of free electrons that reflect radio waves in the frequency range 2 MHz to 30 MHz.", "explanation": "Both A and R are true, and R correctly explains A. The ionosphere''s free electrons (produced by solar UV radiation ionising atmospheric gases) cause total internal reflection of radio waves below the critical frequency. This allows short-wave radio signals (2–30 MHz) to travel thousands of kilometres by bouncing between Earth and ionosphere.", "correct_answer": "A", "concept_tags": ["ionosphere-reflection", "sky-wave", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-comm-25", "subtopic": "ionospheric propagation", "topic_name": "Elements of Communication System", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the free electrons cause the reflection that enables long-distance communication.", "misconception": "Not connecting electron density to wave reflection"}, {"option_key": "C", "hint": "R is correct — the ionosphere does contain free electrons (10¹⁰–10¹² per m³) that reflect radio waves.", "misconception": "Doubting the ionosphere''s electron content"}, {"option_key": "D", "hint": "A is true — shortwave radio has been used for intercontinental communication since the 1920s via ionospheric reflection.", "misconception": "Denying the well-established phenomenon of sky wave communication"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In AM transmission, the carrier wave carries no information.\nReason (R): In amplitude modulation, information is contained in the sideband frequencies, not in the carrier frequency.", "explanation": "Both A and R are true, and R correctly explains A. The carrier is a constant-amplitude, constant-frequency wave that acts as a ''vehicle'' for the message. The actual information is encoded in the sidebands (fc ± fm) created by modulation. This is why the carrier power (which is the dominant power in AM) is essentially wasted, making AM inefficient.", "correct_answer": "A", "concept_tags": ["carrier-no-info", "sidebands-carry-info", "AM-efficiency"], "payload": {"question_id": "cuet-phy-comm-26", "subtopic": "information content in AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is the precise explanation of A — the carrier carries no info because the sidebands carry all the information.", "misconception": "Not seeing the direct logical link"}, {"option_key": "C", "hint": "R is factually correct. In the AM spectrum, removing the carrier and keeping only sidebands still preserves all the message information.", "misconception": "Thinking the carrier contains message information"}, {"option_key": "D", "hint": "A is true — the carrier frequency fc remains constant and carries no varying information.", "misconception": "Confusing the carrier wave with the modulated wave"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Television signals cannot be received beyond a certain distance from the transmitting tower.\nReason (R): TV signals travel as space waves and are limited by the curvature of the Earth.", "explanation": "Both A and R are true, and R correctly explains A. TV signals use VHF/UHF frequencies (above 30 MHz) which propagate as space waves (line-of-sight). They are not reflected by the ionosphere and cannot follow Earth''s curvature. The range is limited to d = √(2Rh), determined by the tower height and Earth''s radius.", "correct_answer": "A", "concept_tags": ["TV-range", "space-wave-limitation", "earth-curvature"], "payload": {"question_id": "cuet-phy-comm-27", "subtopic": "TV signal range limitation", "topic_name": "Propagation of EM Waves", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is the exact reason for A — space wave propagation and Earth''s curvature directly cause the range limitation.", "misconception": "Not connecting propagation mode to range limit"}, {"option_key": "C", "hint": "R is correct — TV signals do propagate as space waves and are limited by Earth''s curvature.", "misconception": "Thinking TV signals use sky wave propagation"}, {"option_key": "D", "hint": "A is true — without satellite relay, TV reception is limited to line-of-sight range from the tower.", "misconception": "Thinking TV signals can travel unlimited distances"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following communication terms (Column-I) with their descriptions (Column-II):\n\nColumn-I: (P) Attenuation (Q) Noise (R) Bandwidth (S) Modulation\nColumn-II: (1) Range of frequencies occupied by a signal (2) Loss of signal strength during transmission (3) Superimposing message on a carrier wave (4) Unwanted signals that distort the message", "explanation": "P→2: Attenuation is the gradual loss of signal strength as it travels through the channel. Q→4: Noise consists of unwanted electrical signals from various sources that corrupt the message. R→1: Bandwidth is the range of frequencies a signal occupies or a channel can handle. S→3: Modulation is the process of combining the message signal with a high-frequency carrier.", "correct_answer": "A", "concept_tags": ["terminology", "matching", "communication-basics"], "payload": {"question_id": "cuet-phy-comm-28", "subtopic": "communication terminology", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "B", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→4, R→3, S→1", "is_correct": false}, {"key": "D", "text": "P→1, Q→4, R→2, S→3", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "P→4 confuses attenuation with noise. Attenuation is signal weakening (2), noise is unwanted signals (4).", "misconception": "Swapping attenuation and noise definitions"}, {"option_key": "C", "hint": "R→3 assigns ''superimposing on carrier'' to bandwidth. Bandwidth is about frequency range (1), not modulation.", "misconception": "Confusing bandwidth with modulation"}, {"option_key": "D", "hint": "P→1 assigns ''frequency range'' to attenuation. Attenuation is about signal strength loss, not frequency.", "misconception": "Confusing attenuation with bandwidth"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following frequency ranges (Column-I) with their propagation modes (Column-II):\n\nColumn-I: (P) Below 2 MHz (Q) 2–30 MHz (R) Above 30 MHz (S) Above 3 GHz\nColumn-II: (1) Satellite communication (2) Sky wave (ionospheric) (3) Ground wave (surface) (4) Space wave (line-of-sight)", "explanation": "P→3: Below 2 MHz uses ground wave propagation along Earth''s surface (AM radio). Q→2: 2–30 MHz uses sky wave — reflected by the ionosphere (shortwave radio). R→4: Above 30 MHz uses space wave — line-of-sight propagation (TV, FM). S→1: Above 3 GHz uses satellite communication — passes through ionosphere to geostationary satellites.", "correct_answer": "B", "concept_tags": ["frequency-propagation-mapping", "matching", "modes"], "payload": {"question_id": "cuet-phy-comm-29", "subtopic": "propagation mode vs frequency", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→4, R→2, S→1", "is_correct": false}, {"key": "B", "text": "P→3, Q→2, R→4, S→1", "is_correct": true}, {"key": "C", "text": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→1, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→4 assigns space wave to 2–30 MHz. This range actually uses sky wave (ionospheric reflection).", "misconception": "Swapping sky wave and space wave"}, {"option_key": "C", "hint": "P→2 assigns sky wave to below 2 MHz. Low frequencies use ground wave, not sky wave.", "misconception": "Swapping ground wave and sky wave"}, {"option_key": "D", "hint": "R→1 assigns satellite to above 30 MHz and S→4 assigns space wave to above 3 GHz. It''s the reverse.", "misconception": "Swapping satellite and space wave ranges"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following parameters of AM wave (Column-I) with their expressions (Column-II):\n\nColumn-I: (P) Modulation index (Q) Bandwidth of AM (R) Power of AM wave (S) Upper sideband frequency\nColumn-II: (1) fc + fm (2) Pc(1 + m²/2) (3) Am/Ac (4) 2fm", "explanation": "P→3: Modulation index m = Am/Ac (ratio of message amplitude to carrier amplitude). Q→4: AM bandwidth = 2fm (twice the modulating frequency). R→2: Total AM power = Pc(1 + m²/2). S→1: Upper sideband frequency = fc + fm.", "correct_answer": "C", "concept_tags": ["AM-formulas", "matching", "key-expressions"], "payload": {"question_id": "cuet-phy-comm-30", "subtopic": "AM formulas", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "B", "text": "P→4, Q→3, R→2, S→1", "is_correct": false}, {"key": "C", "text": "P→3, Q→4, R→2, S→1", "is_correct": true}, {"key": "D", "text": "P→3, Q→4, R→1, S→2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→1 assigns fc + fm to bandwidth. fc + fm is the upper sideband frequency, not the bandwidth.", "misconception": "Confusing sideband frequency with bandwidth"}, {"option_key": "B", "hint": "P→4 assigns 2fm to modulation index. 2fm is the bandwidth, and Am/Ac is the modulation index.", "misconception": "Swapping modulation index and bandwidth expressions"}, {"option_key": "D", "hint": "R→1 assigns fc + fm to power. AM power is Pc(1 + m²/2), not related to fc + fm.", "misconception": "Confusing power expression with frequency expression"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In a communication system, the transmitter and receiver must operate at the same frequency for successful communication.", "explanation": "This statement is TRUE. The receiver must be tuned to the same carrier frequency as the transmitter to successfully receive and demodulate the signal. If the receiver is tuned to a different frequency, it will pick up a different station or no signal at all. This is the principle behind tuning a radio to a specific station.", "correct_answer": "A", "concept_tags": ["tuning", "frequency-matching", "receiver"], "payload": {"question_id": "cuet-phy-comm-31", "subtopic": "tuning principle", "topic_name": "Elements of Communication System", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If receiver and transmitter frequencies don''t match, the receiver''s tuning circuit won''t select the intended signal.", "misconception": "Thinking any receiver can pick up any frequency without tuning"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Frequencies above 30 MHz cannot be reflected by the ionosphere.", "explanation": "This statement is TRUE. The ionosphere can only reflect radio waves below the critical frequency (typically up to about 30 MHz, depending on electron density). Frequencies above 30 MHz penetrate through the ionosphere into space, which is why VHF TV signals and FM radio cannot use sky wave propagation and require line-of-sight towers.", "correct_answer": "A", "concept_tags": ["ionosphere-limit", "critical-frequency", "VHF"], "payload": {"question_id": "cuet-phy-comm-32", "subtopic": "ionospheric frequency limit", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is why TV transmitters need tall towers — their VHF/UHF signals pass through the ionosphere instead of bouncing back.", "misconception": "Thinking the ionosphere reflects all radio frequencies"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "medium", "question_text": "In amplitude modulation, the frequency of the modulated wave remains the same as the carrier frequency.", "explanation": "This statement is FALSE. While the central (dominant) frequency is the carrier frequency, the modulated wave actually contains three frequencies: fc, fc + fm, and fc − fm. The AM wave is not a single frequency — it spans a bandwidth of 2fm around the carrier. However, the carrier frequency component itself remains unchanged.", "correct_answer": "B", "concept_tags": ["AM-frequencies", "sidebands", "frequency-content"], "payload": {"question_id": "cuet-phy-comm-33", "subtopic": "frequency content of AM wave", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The AM wave contains sideband frequencies (fc ± fm) in addition to the carrier. It is NOT a single-frequency wave.", "misconception": "Thinking AM only changes amplitude without adding new frequencies"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-bandwidth", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "medium", "question_text": "A video signal requires more bandwidth than an audio signal.", "explanation": "This statement is TRUE. A video signal has a bandwidth of about 4.2 MHz (analog TV), while an audio signal requires only about 20 kHz (music) or 3 kHz (speech). Video requires vastly more bandwidth because it carries two-dimensional spatial information changing rapidly in time, while audio is a one-dimensional signal.", "correct_answer": "A", "concept_tags": ["video-bandwidth", "audio-bandwidth", "comparison"], "payload": {"question_id": "cuet-phy-comm-34", "subtopic": "bandwidth comparison", "topic_name": "Bandwidth of Signals and Channels", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Video bandwidth (~4.2 MHz) is about 200× more than music bandwidth (~20 kHz). More information requires more bandwidth.", "misconception": "Thinking audio and video need similar bandwidths"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-detection", "exam_ids": ["CUET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The device used for selecting a desired station in a radio receiver is called a ______.", "explanation": "A band-pass filter (or tuning circuit, typically an LC circuit) is used to select a specific radio station. It allows only a narrow band of frequencies (around the desired station''s carrier frequency) to pass through while rejecting all other stations. Tuning the radio changes the resonant frequency of this LC circuit.", "correct_answer": "A", "concept_tags": ["band-pass-filter", "tuning", "station-selection"], "payload": {"question_id": "cuet-phy-comm-35", "subtopic": "receiver tuning", "topic_name": "Detection and Demodulation", "bloom_level": "remember", "options": [{"key": "A", "text": "Band-pass filter (tuning circuit)", "is_correct": true}, {"key": "B", "text": "Low-pass filter", "is_correct": false}, {"key": "C", "text": "Rectifier", "is_correct": false}, {"key": "D", "text": "Demodulator", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low-pass filter passes all frequencies below a cutoff. For station selection, you need to select a narrow band — that''s a band-pass filter.", "misconception": "Confusing low-pass with band-pass filtering"}, {"option_key": "C", "hint": "A rectifier (diode) is used in the detection stage after station selection, not for selecting the station.", "misconception": "Confusing detection with tuning"}, {"option_key": "D", "hint": "A demodulator extracts the message from the carrier. It operates after the desired station has been selected.", "misconception": "Confusing demodulation with station selection"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The modulation index m of an AM wave whose maximum and minimum amplitudes are 10 V and 4 V respectively is ______.", "explanation": "m = (Amax − Amin)/(Amax + Amin) = (10 − 4)/(10 + 4) = 6/14 = 3/7 ≈ 0.43. This formula is derived from Amax = Ac(1+m) and Amin = Ac(1−m). Subtracting: Amax − Amin = 2mAc. Adding: Amax + Amin = 2Ac. Dividing: m = (Amax − Amin)/(Amax + Amin).", "correct_answer": "B", "concept_tags": ["modulation-index-formula", "Amax-Amin-method", "numerical"], "payload": {"question_id": "cuet-phy-comm-36", "subtopic": "modulation index from amplitudes", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "0.6", "is_correct": false}, {"key": "B", "text": "3/7 ≈ 0.43", "is_correct": true}, {"key": "C", "text": "0.4", "is_correct": false}, {"key": "D", "text": "2.5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.6 = 6/10, which would use m = (Amax − Amin)/Amax. The correct formula divides by (Amax + Amin).", "misconception": "Using wrong denominator in the formula"}, {"option_key": "C", "hint": "0.4 = 4/10 = Amin/Amax, which is not the modulation index formula.", "misconception": "Using ratio of min to max instead of the correct formula"}, {"option_key": "D", "hint": "2.5 = 10/4 = Amax/Amin. The modulation index must be ≤ 1 for distortion-free AM.", "misconception": "Using the amplitude ratio instead of the modulation formula"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The loss of signal strength as it propagates through the communication channel is called ______.", "explanation": "Attenuation is the gradual decrease in signal amplitude (strength) as the signal travels through the channel. It occurs due to spreading of energy, absorption by the medium, and scattering. Attenuation is measured in decibels (dB) and is a major reason why repeaters and amplifiers are needed in long-distance communication.", "correct_answer": "C", "concept_tags": ["attenuation", "signal-loss", "channel"], "payload": {"question_id": "cuet-phy-comm-37", "subtopic": "signal attenuation", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Noise", "is_correct": false}, {"key": "B", "text": "Distortion", "is_correct": false}, {"key": "C", "text": "Attenuation", "is_correct": true}, {"key": "D", "text": "Interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Noise is unwanted signal added to the original — it doesn''t reduce the signal, it corrupts it.", "misconception": "Confusing signal corruption with signal weakening"}, {"option_key": "B", "hint": "Distortion changes the shape/waveform of the signal, not its overall strength.", "misconception": "Confusing waveform change with amplitude loss"}, {"option_key": "D", "hint": "Interference is when multiple signals combine and disrupt each other. Attenuation is loss of a single signal''s strength.", "misconception": "Confusing multi-signal interaction with single-signal weakening"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A radio station broadcasts at a carrier frequency of 1200 kHz. The station uses amplitude modulation with audio signals ranging from 100 Hz to 5 kHz.\n\nThe range of frequencies occupied by the AM broadcast is:", "explanation": "The AM signal extends from fc − fm(max) to fc + fm(max). Here fc = 1200 kHz and fm(max) = 5 kHz. Lower limit = 1200 − 5 = 1195 kHz. Upper limit = 1200 + 5 = 1205 kHz. The AM broadcast occupies 1195 kHz to 1205 kHz, a bandwidth of 10 kHz.", "correct_answer": "A", "concept_tags": ["AM-spectrum-range", "sideband-extent", "scenario"], "payload": {"question_id": "cuet-phy-comm-38", "subtopic": "frequency occupation of AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1195 kHz to 1205 kHz", "is_correct": true}, {"key": "B", "text": "1199.9 kHz to 1205 kHz", "is_correct": false}, {"key": "C", "text": "100 Hz to 1205 kHz", "is_correct": false}, {"key": "D", "text": "1195 kHz to 1200 kHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1199.9 kHz uses the minimum audio frequency (100 Hz = 0.1 kHz). The full extent uses the maximum: 5 kHz from the carrier.", "misconception": "Using minimum modulating frequency for the sideband extent"}, {"option_key": "C", "hint": "The original audio frequencies (100 Hz to 5 kHz) are NOT present in the AM signal. Only the shifted sidebands around fc exist.", "misconception": "Including baseband frequencies in the AM spectrum"}, {"option_key": "D", "hint": "This shows only the lower sideband. AM produces both upper and lower sidebands symmetrically around fc.", "misconception": "Forgetting the upper sideband"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A transmitting antenna at the top of a tower has a height of 45 m and the receiving antenna has a height of 80 m. Calculate the maximum line-of-sight distance between them. (R = 6400 km)", "explanation": "Maximum LOS distance = √(2Rh₁) + √(2Rh₂). d₁ = √(2 × 6.4 × 10⁶ × 45) = √(5.76 × 10⁸) = 2.4 × 10⁴ m = 24 km. d₂ = √(2 × 6.4 × 10⁶ × 80) = √(10.24 × 10⁸) = 3.2 × 10⁴ m = 32 km. Total = 24 + 32 = 56 km.", "correct_answer": "C", "concept_tags": ["two-antenna-LOS", "numerical", "range-formula"], "payload": {"question_id": "cuet-phy-comm-39", "subtopic": "two-antenna range calculation", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "24 km", "is_correct": false}, {"key": "B", "text": "32 km", "is_correct": false}, {"key": "C", "text": "56 km", "is_correct": true}, {"key": "D", "text": "112 km", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "24 km is only the range of the transmitting antenna (h = 45 m). You must add the receiving antenna''s range too.", "misconception": "Calculating range of only one antenna"}, {"option_key": "B", "hint": "32 km is only the range of the receiving antenna (h = 80 m). Total LOS = d₁ + d₂.", "misconception": "Calculating range of only the taller antenna"}, {"option_key": "D", "hint": "112 km = 2 × 56 km. There is no factor of 2 in the two-antenna formula: dmax = d₁ + d₂.", "misconception": "Doubling the correct answer erroneously"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A carrier wave of peak voltage 12 V is used to transmit a message signal. The modulated signal has a maximum voltage of 18 V and a minimum voltage of 6 V.\n\nThe percentage modulation and the peak voltage of the modulating signal are:", "explanation": "Carrier amplitude Ac = 12 V. Amax = 18 V = Ac + Am, so Am = 18 − 12 = 6 V. Verification: Amin = Ac − Am = 12 − 6 = 6 V ✓. Modulation index m = Am/Ac = 6/12 = 0.5. Percentage modulation = 50%. Alternatively: m = (Amax − Amin)/(Amax + Amin) = (18 − 6)/(18 + 6) = 12/24 = 0.5.", "correct_answer": "B", "concept_tags": ["percentage-modulation", "peak-voltage", "AM-calculation"], "payload": {"question_id": "cuet-phy-comm-40", "subtopic": "modulation index and signal amplitude", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "75% and 9 V", "is_correct": false}, {"key": "B", "text": "50% and 6 V", "is_correct": true}, {"key": "C", "text": "50% and 12 V", "is_correct": false}, {"key": "D", "text": "33% and 4 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "75% means m = 0.75, which gives Amax = 12(1+0.75) = 21 V, not 18 V.", "misconception": "Incorrectly calculating modulation index"}, {"option_key": "C", "hint": "Peak voltage of modulating signal Am = 6 V, not 12 V. 12 V is the carrier amplitude Ac.", "misconception": "Confusing message amplitude with carrier amplitude"}, {"option_key": "D", "hint": "33% gives m = 0.33, so Amax = 12(1.33) = 16 V, not 18 V. Check: m = (18−6)/(18+6) = 0.5.", "misconception": "Using wrong formula or arithmetic error"}]}}]'::jsonb, 'deploy-2026-03-05-b01');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following materials is an example of a non-ohmic conductor?", "explanation": "A semiconductor diode (p-n junction diode) is a non-ohmic conductor because its V-I characteristic is non-linear; the current through it does not vary linearly with the applied voltage. Copper, aluminium, and silver are ohmic conductors that obey Ohm''s law at constant temperature.", "correct_answer": "C", "concept_tags": ["ohms-law", "non-ohmic-conductor", "V-I-characteristics"], "payload": {"question_id": "cuet-phy-current-ohm-01", "subtopic": "V-I Characteristics", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Copper wire", "is_correct": false}, {"key": "B", "text": "Aluminium wire", "is_correct": false}, {"key": "C", "text": "Semiconductor diode", "is_correct": true}, {"key": "D", "text": "Silver wire", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Copper is a metal that obeys Ohm''s law at constant temperature, producing a linear V-I graph.", "misconception": "Thinking all conductors are non-ohmic"}, {"option_key": "B", "hint": "Aluminium, like copper, is a metallic conductor that follows Ohm''s law under constant physical conditions.", "misconception": null}, {"option_key": "D", "hint": "Silver is an excellent metallic conductor that follows Ohm''s law. It has the highest electrical conductivity among metals.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electrical conductivity is:", "explanation": "Conductivity sigma = 1/rho, where rho has units of ohm-metre (Ω·m). Therefore, conductivity has units of (Ω·m)⁻¹ = Ω⁻¹m⁻¹, which can also be written as S/m (siemens per metre) or mho/m.", "correct_answer": "A", "concept_tags": ["conductivity", "SI-units", "resistivity"], "payload": {"question_id": "cuet-phy-current-ohm-02", "subtopic": "Conductivity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Ω⁻¹m⁻¹", "is_correct": true}, {"key": "B", "text": "Ω·m", "is_correct": false}, {"key": "C", "text": "Ω⁻¹m", "is_correct": false}, {"key": "D", "text": "Ω·m⁻¹", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Ω·m is the unit of resistivity, not conductivity. Conductivity is the reciprocal of resistivity.", "misconception": "Confusing the unit of resistivity with conductivity"}, {"option_key": "C", "hint": "Ω⁻¹m would be obtained only if resistivity had units of Ω/m, which is incorrect.", "misconception": "Incorrect dimensional analysis of conductivity"}, {"option_key": "D", "hint": "Ω·m⁻¹ does not correctly represent the reciprocal of Ω·m. The reciprocal of Ω·m is Ω⁻¹m⁻¹.", "misconception": "Only inverting one part of the compound unit"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Ohm''s law, the current flowing through a conductor is:", "explanation": "Ohm''s law states that V = IR, which means I = V/R. The current through a conductor is directly proportional to the potential difference across its ends and inversely proportional to its resistance, provided physical conditions like temperature remain constant.", "correct_answer": "B", "concept_tags": ["ohms-law", "current", "voltage", "resistance"], "payload": {"question_id": "cuet-phy-current-ohm-03", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Directly proportional to resistance", "is_correct": false}, {"key": "B", "text": "Directly proportional to potential difference and inversely proportional to resistance", "is_correct": true}, {"key": "C", "text": "Inversely proportional to potential difference", "is_correct": false}, {"key": "D", "text": "Independent of potential difference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If current were directly proportional to resistance, increasing resistance would increase current, which contradicts Ohm''s law (I = V/R).", "misconception": "Confusing direct and inverse proportionality with resistance"}, {"option_key": "C", "hint": "Current is directly (not inversely) proportional to potential difference. Doubling V doubles I when R is constant.", "misconception": "Reversing the proportionality relationship with voltage"}, {"option_key": "D", "hint": "Current depends on potential difference; without a potential difference, no current flows through the conductor.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electrical resistivity is:", "explanation": "Resistivity ρ is defined by R = ρl/A, so ρ = RA/l. The unit of resistance is ohm (Ω), area is m², and length is m. Therefore, the unit of resistivity is Ω·m² / m = Ω·m.", "correct_answer": "C", "concept_tags": ["resistivity", "SI-units", "resistance"], "payload": {"question_id": "cuet-phy-current-ohm-04", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Ω/m", "is_correct": false}, {"key": "B", "text": "Ω/m²", "is_correct": false}, {"key": "C", "text": "Ω·m", "is_correct": true}, {"key": "D", "text": "Ω·m²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Ω/m would imply resistivity decreases with length, but from ρ = RA/l the correct dimensional analysis gives Ω·m.", "misconception": "Incorrectly dividing by length instead of multiplying"}, {"option_key": "B", "hint": "Ω/m² does not follow from ρ = RA/l. The area appears in the numerator, not the denominator of ρ.", "misconception": null}, {"option_key": "D", "hint": "Ω·m² has an extra power of length. Dimensional analysis of ρ = RA/l gives Ω·m, not Ω·m².", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The drift velocity of free electrons in a conductor is of the order of:", "explanation": "The drift velocity of electrons in a metallic conductor carrying typical current is very small, of the order of 10⁻⁴ m/s (about 0.1 mm/s). This is because although electrons move randomly at high thermal speeds (~10⁶ m/s), the net drift due to the electric field is extremely slow.", "correct_answer": "A", "concept_tags": ["drift-velocity", "free-electrons", "conductor"], "payload": {"question_id": "cuet-phy-current-ohm-05", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "10⁻⁴ m/s", "is_correct": true}, {"key": "B", "text": "10⁻¹⁰ m/s", "is_correct": false}, {"key": "C", "text": "3 × 10⁸ m/s", "is_correct": false}, {"key": "D", "text": "10⁶ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "10⁻¹⁰ m/s is far too small even for drift velocity. Typical drift velocities are around 10⁻⁴ m/s.", "misconception": null}, {"option_key": "C", "hint": "3 × 10⁸ m/s is the speed of light (speed of the electric signal), not the drift speed of electrons.", "misconception": "Confusing signal propagation speed with electron drift velocity"}, {"option_key": "D", "hint": "10⁶ m/s is close to the thermal (random) speed of electrons, not their drift velocity in an applied field.", "misconception": "Confusing thermal velocity with drift velocity"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The reciprocal of resistivity is called:", "explanation": "Conductivity (σ) is defined as the reciprocal of resistivity (ρ), i.e., σ = 1/ρ. Its SI unit is Ω⁻¹m⁻¹ or S/m (siemens per metre). It measures how easily a material allows current to flow through it.", "correct_answer": "D", "concept_tags": ["conductivity", "resistivity", "reciprocal"], "payload": {"question_id": "cuet-phy-current-ohm-06", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "Conductance", "is_correct": false}, {"key": "B", "text": "Susceptance", "is_correct": false}, {"key": "C", "text": "Reluctance", "is_correct": false}, {"key": "D", "text": "Conductivity", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Conductance (G = 1/R) is the reciprocal of resistance, not resistivity. Conductivity is the reciprocal of resistivity.", "misconception": "Confusing conductance (1/R) with conductivity (1/ρ)"}, {"option_key": "B", "hint": "Susceptance is the imaginary part of admittance in AC circuits and is unrelated to the reciprocal of resistivity.", "misconception": null}, {"option_key": "C", "hint": "Reluctance is a quantity in magnetic circuits (analogous to resistance) and has no relation to the reciprocal of resistivity.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A copper wire has a resistance of 8 Ω at 20°C. If the temperature coefficient of resistance for copper is 3.9 × 10⁻³ per °C, the resistance of the wire at 100°C is approximately:", "explanation": "Using R_T = R_0(1 + alpha × ΔT), where R_0 = 8 Ω, alpha = 3.9 × 10⁻³ per °C, and ΔT = 100 - 20 = 80°C. R_100 = 8 × (1 + 3.9 × 10⁻³ × 80) = 8 × (1 + 0.312) = 8 × 1.312 = 10.496 Ω ≈ 10.5 Ω.", "correct_answer": "B", "concept_tags": ["temperature-coefficient", "resistance", "metals"], "payload": {"question_id": "cuet-phy-current-ohm-07", "subtopic": "Temperature Dependence of Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "8.31 Ω", "is_correct": false}, {"key": "B", "text": "10.5 Ω", "is_correct": true}, {"key": "C", "text": "12.8 Ω", "is_correct": false}, {"key": "D", "text": "11.1 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.31 Ω would result from using ΔT = 10°C instead of 80°C; make sure you compute the full temperature difference.", "misconception": "Using incorrect temperature change"}, {"option_key": "C", "hint": "12.8 Ω would result from using alpha = 0.006 per °C, which is not the stated value for copper.", "misconception": "Using wrong temperature coefficient"}, {"option_key": "D", "hint": "11.1 Ω does not match the correct calculation R = 8 × (1 + 3.9×10⁻³ × 80) = 10.5 Ω.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Three resistors of 6 Ω, 3 Ω, and 2 Ω are connected in parallel. The equivalent resistance of the combination is:", "explanation": "For resistors in parallel: 1/R_eq = 1/R₁ + 1/R₂ + 1/R₃ = 1/6 + 1/3 + 1/2 = 1/6 + 2/6 + 3/6 = 6/6 = 1. Therefore R_eq = 1 Ω. The equivalent resistance in a parallel combination is always less than the smallest individual resistance.", "correct_answer": "D", "concept_tags": ["parallel-combination", "equivalent-resistance", "resistors"], "payload": {"question_id": "cuet-phy-current-ohm-08", "subtopic": "Series and Parallel Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "11 Ω", "is_correct": false}, {"key": "B", "text": "2 Ω", "is_correct": false}, {"key": "C", "text": "3 Ω", "is_correct": false}, {"key": "D", "text": "1 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "11 Ω is the sum 6+3+2, which is the equivalent resistance for a series combination, not parallel.", "misconception": "Using series formula instead of parallel formula"}, {"option_key": "B", "hint": "2 Ω is the smallest resistor, but the parallel equivalent must be less than the smallest individual resistance.", "misconception": "Thinking parallel resistance equals the smallest resistance"}, {"option_key": "C", "hint": "3 Ω is one of the individual resistances and does not correspond to the parallel combination result.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the drift velocity of electrons in a conductor is doubled while the number density of free electrons remains the same, the current through the conductor:", "explanation": "Current I = nAv_d, where n is the number density, A is the cross-sectional area, and v_d is the drift velocity. If v_d is doubled and all other quantities remain constant, the current I also doubles. Current is directly proportional to drift velocity.", "correct_answer": "B", "concept_tags": ["drift-velocity", "current", "number-density"], "payload": {"question_id": "cuet-phy-current-ohm-09", "subtopic": "Drift Velocity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Remains the same", "is_correct": false}, {"key": "B", "text": "Gets doubled", "is_correct": true}, {"key": "C", "text": "Gets halved", "is_correct": false}, {"key": "D", "text": "Becomes four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since I = nAv_d, changing v_d must change the current. It cannot remain the same.", "misconception": "Thinking current is independent of drift velocity"}, {"option_key": "C", "hint": "The relation is I = nAv_d (direct proportionality), so doubling v_d doubles I, not halves it.", "misconception": "Assuming inverse proportionality between current and drift velocity"}, {"option_key": "D", "hint": "I is directly proportional to v_d (not v_d²), so doubling v_d doubles I, not quadruples it.", "misconception": "Confusing linear and quadratic dependence"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a resistor colour code, the sequence of bands is yellow, violet, orange, and gold. The value of the resistance is:", "explanation": "In the colour code: Yellow = 4, Violet = 7, Orange = 10³ (multiplier), Gold = ±5% tolerance. The resistance = 47 × 10³ = 47,000 Ω = 47 kΩ with ±5% tolerance.", "correct_answer": "C", "concept_tags": ["colour-code", "resistor", "tolerance"], "payload": {"question_id": "cuet-phy-current-ohm-10", "subtopic": "Colour Code of Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "4.7 kΩ ± 5%", "is_correct": false}, {"key": "B", "text": "470 Ω ± 5%", "is_correct": false}, {"key": "C", "text": "47 kΩ ± 5%", "is_correct": true}, {"key": "D", "text": "470 kΩ ± 5%", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4.7 kΩ would result from using orange as 10² instead of 10³. Orange represents the multiplier 10³.", "misconception": "Misassigning the multiplier value for orange"}, {"option_key": "B", "hint": "470 Ω corresponds to yellow-violet-brown (10¹ multiplier), not yellow-violet-orange (10³ multiplier).", "misconception": "Confusing brown and orange multipliers"}, {"option_key": "D", "hint": "470 kΩ would require a multiplier of 10⁴ (yellow band), but the third band is orange (10³).", "misconception": "Using incorrect multiplier exponent"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wire of resistance 12 Ω is stretched uniformly until its length becomes three times the original length. The new resistance of the wire is:", "explanation": "When a wire is stretched, its volume remains constant: A₁l₁ = A₂l₂. If l₂ = 3l₁, then A₂ = A₁/3. Using R = ρl/A, the new resistance R₂ = ρ(3l₁)/(A₁/3) = 9ρl₁/A₁ = 9R₁ = 9 × 12 = 108 Ω. When length increases n times, resistance increases n² times.", "correct_answer": "D", "concept_tags": ["resistance", "stretching-wire", "resistivity", "volume-conservation"], "payload": {"question_id": "cuet-phy-current-ohm-11", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "36 Ω", "is_correct": false}, {"key": "B", "text": "4 Ω", "is_correct": false}, {"key": "C", "text": "48 Ω", "is_correct": false}, {"key": "D", "text": "108 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "36 Ω = 3 × 12 would result if only the length change were considered without accounting for the decrease in cross-sectional area.", "misconception": "Forgetting that stretching also reduces the cross-sectional area"}, {"option_key": "B", "hint": "4 Ω = 12/3 would result from incorrectly dividing by the stretch factor instead of multiplying by its square.", "misconception": "Thinking resistance decreases when wire is stretched"}, {"option_key": "C", "hint": "48 Ω does not correspond to any correct application of R = ρl/A with volume conservation.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current density in a copper wire of cross-sectional area 2 × 10⁻⁶ m² carrying a current of 4 A is:", "explanation": "Current density J = I/A = 4 / (2 × 10⁻⁶) = 2 × 10⁶ A/m². Current density is a vector quantity that gives the amount of current flowing per unit cross-sectional area perpendicular to the flow direction.", "correct_answer": "B", "concept_tags": ["current-density", "cross-sectional-area", "current"], "payload": {"question_id": "cuet-phy-current-ohm-12", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "8 × 10⁻⁶ A/m²", "is_correct": false}, {"key": "B", "text": "2 × 10⁶ A/m²", "is_correct": true}, {"key": "C", "text": "2 × 10⁻⁶ A/m²", "is_correct": false}, {"key": "D", "text": "8 × 10⁶ A/m²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8 × 10⁻⁶ A/m² results from multiplying I and A instead of dividing. J = I/A, not I × A.", "misconception": "Multiplying current and area instead of dividing"}, {"option_key": "C", "hint": "2 × 10⁻⁶ is the value of the area itself, not the current density. J = 4/(2×10⁻⁶) = 2×10⁶.", "misconception": null}, {"option_key": "D", "hint": "8 × 10⁶ would result from incorrectly using J = I × A × some factor. The correct calculation gives 2 × 10⁶.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wire of resistance R is cut into 4 equal parts and all parts are connected in parallel. The equivalent resistance of the combination is:", "explanation": "When a wire of resistance R is cut into 4 equal parts, each part has resistance R/4. When four resistances each of R/4 are connected in parallel, the equivalent resistance is (R/4)/4 = R/16. In general, cutting a wire into n equal parts and connecting them in parallel gives R/n².", "correct_answer": "A", "concept_tags": ["resistance", "parallel-combination", "equivalent-resistance"], "payload": {"question_id": "cuet-phy-current-ohm-13", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "R/16", "is_correct": true}, {"key": "B", "text": "R/4", "is_correct": false}, {"key": "C", "text": "4R", "is_correct": false}, {"key": "D", "text": "R/8", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R/4 is the resistance of each individual piece. Connecting them in parallel further reduces the total resistance to R/16.", "misconception": "Forgetting to calculate the parallel combination after cutting"}, {"option_key": "C", "hint": "4R would be the result of connecting four resistances of R in series, not parallel pieces of a cut wire.", "misconception": "Confusing series and parallel combinations"}, {"option_key": "D", "hint": "R/8 would result if only 2 pieces were connected in parallel (each R/4, giving R/8 for two in parallel), not all four.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mobility of charge carriers in a conductor is defined as:", "explanation": "Mobility (μ) of a charge carrier is defined as the magnitude of drift velocity per unit electric field, i.e., μ = vd/E. Its SI unit is m²/(V·s). Mobility indicates how quickly a charge carrier can move through a material under the influence of an electric field.", "correct_answer": "C", "concept_tags": ["mobility", "drift-velocity", "electric-field"], "payload": {"question_id": "cuet-phy-current-ohm-14", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Drift velocity per unit current", "is_correct": false}, {"key": "B", "text": "Current density per unit electric field", "is_correct": false}, {"key": "C", "text": "Drift velocity per unit electric field", "is_correct": true}, {"key": "D", "text": "Electric field per unit drift velocity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Mobility relates drift velocity to electric field, not to current. μ = vd/E, and current does not appear in the definition.", "misconception": null}, {"option_key": "B", "hint": "Current density per unit electric field gives conductivity (σ = J/E), not mobility.", "misconception": "Confusing conductivity with mobility"}, {"option_key": "D", "hint": "E/vd is the inverse of mobility. Mobility is vd/E, not E/vd.", "misconception": "Inverting the definition of mobility"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two wires A and B of the same material have lengths in the ratio 1:2 and diameters in the ratio 2:1. The ratio of their resistances R_A : R_B is:", "explanation": "R = ρl/A = ρl/(πd²/4). So R ∝ l/d². For wire A: R_A ∝ 1/4 and for wire B: R_B ∝ 2/1 = 2. Therefore R_A/R_B = (1/4)/2 = 1/8. Wire B has 8 times the resistance of wire A due to being longer and thinner.", "correct_answer": "A", "concept_tags": ["resistance", "length", "diameter", "cross-section"], "payload": {"question_id": "cuet-phy-current-ohm-15", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "1 : 8", "is_correct": true}, {"key": "B", "text": "1 : 4", "is_correct": false}, {"key": "C", "text": "1 : 2", "is_correct": false}, {"key": "D", "text": "2 : 1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1:4 would result from using R ∝ l/d instead of R ∝ l/d², ignoring that area depends on the square of the diameter.", "misconception": "Forgetting to square the diameter ratio in resistance calculation"}, {"option_key": "C", "hint": "1:2 only considers the length ratio and completely ignores the difference in diameters.", "misconception": "Ignoring the effect of cross-sectional area on resistance"}, {"option_key": "D", "hint": "2:1 reverses the ratio. Wire A has a larger cross-section and shorter length, so it has less resistance, not more.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a colour code of carbon resistors, a resistor has bands: brown, black, red, and gold. The value of the resistance is:", "explanation": "In the colour code, brown = 1, black = 0, red = multiplier 10² = 100, and gold = ±5% tolerance. The resistance value = 10 × 100 = 1000 Ω = 1 kΩ with ±5% tolerance. The first two bands give the significant digits and the third band gives the multiplier.", "correct_answer": "D", "concept_tags": ["colour-code", "carbon-resistor", "resistance-value"], "payload": {"question_id": "cuet-phy-current-ohm-16", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "100 Ω ± 5%", "is_correct": false}, {"key": "B", "text": "10 kΩ ± 5%", "is_correct": false}, {"key": "C", "text": "1 kΩ ± 10%", "is_correct": false}, {"key": "D", "text": "1 kΩ ± 5%", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "100 Ω would require the multiplier band to be brown (10¹), not red (10²). The correct value is 10 × 10² = 1000 Ω.", "misconception": "Misreading the multiplier band"}, {"option_key": "B", "hint": "10 kΩ = 10,000 Ω would require the multiplier to be 10³ (orange), not 10² (red).", "misconception": null}, {"option_key": "C", "hint": "The tolerance for gold is ±5%, not ±10%. Silver gives ±10% tolerance.", "misconception": "Confusing gold (±5%) with silver (±10%) tolerance band"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of resistance 20 Ω is bent into a complete circle. The effective resistance between two diametrically opposite points is:", "explanation": "When a wire of resistance 20 Ω is bent into a circle, it forms two semicircular arcs. Each semicircular arc has resistance 20/2 = 10 Ω. Between diametrically opposite points, these two 10 Ω arcs are connected in parallel. R_eq = (10 × 10)/(10 + 10) = 100/20 = 5 Ω.", "correct_answer": "A", "concept_tags": ["resistance", "parallel-combination", "circular-wire"], "payload": {"question_id": "cuet-phy-current-ohm-17", "subtopic": "Series and Parallel Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "5 Ω", "is_correct": true}, {"key": "B", "text": "10 Ω", "is_correct": false}, {"key": "C", "text": "20 Ω", "is_correct": false}, {"key": "D", "text": "2.5 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "10 Ω is the resistance of one semicircular half alone. The two halves are in parallel, giving a smaller value.", "misconception": "Forgetting that the two halves are in parallel"}, {"option_key": "C", "hint": "20 Ω is the total resistance of the entire wire. Bending into a circle and measuring across a diameter yields a parallel combination.", "misconception": "Using total wire resistance without considering the parallel paths"}, {"option_key": "D", "hint": "2.5 Ω would result from assuming four equal segments in parallel, which does not apply to diametrically opposite points.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The relaxation time of free electrons in a metallic conductor is 2.5 × 10⁻¹⁴ s. If the number density of free electrons is 8.5 × 10²⁸ m⁻³ and the mass of an electron is 9.1 × 10⁻³¹ kg, the resistivity of the conductor is approximately:", "explanation": "Resistivity rho = m/(ne²τ), where m = 9.1 × 10⁻³¹ kg, n = 8.5 × 10²⁸ m⁻³, e = 1.6 × 10⁻¹⁹ C, τ = 2.5 × 10⁻¹⁴ s. rho = (9.1 × 10⁻³¹)/((8.5 × 10²⁸)(1.6 × 10⁻¹⁹)²(2.5 × 10⁻¹⁴)) = (9.1 × 10⁻³¹)/((8.5 × 10²⁸)(2.56 × 10⁻³⁸)(2.5 × 10⁻¹⁴)) = (9.1 × 10⁻³¹)/(5.44 × 10⁻²³) ≈ 1.67 × 10⁻⁸ Ω·m ≈ 1.7 × 10⁻⁸ Ω·m.", "correct_answer": "D", "concept_tags": ["resistivity", "relaxation-time", "drift-velocity", "free-electrons"], "payload": {"question_id": "cuet-phy-current-ohm-18", "subtopic": "Resistivity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "1.7 × 10⁻⁶ Ω·m", "is_correct": false}, {"key": "B", "text": "1.7 × 10⁻⁴ Ω·m", "is_correct": false}, {"key": "C", "text": "1.7 × 10⁻² Ω·m", "is_correct": false}, {"key": "D", "text": "1.7 × 10⁻⁸ Ω·m", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1.7 × 10⁻⁶ is 100 times too large. Check that e² = (1.6×10⁻¹⁹)² = 2.56×10⁻³⁸ is correctly used.", "misconception": "Error in computing e² exponent"}, {"option_key": "B", "hint": "1.7 × 10⁻⁴ is far too large for a metallic conductor. Typical metals have resistivities of the order 10⁻⁸ Ω·m.", "misconception": "Major arithmetic error in exponent calculation"}, {"option_key": "C", "hint": "1.7 × 10⁻² Ω·m is in the range of semiconductors, not metals. The given data corresponds to a metal.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A cylindrical conductor of length l and radius r has resistance R. If it is reshaped into a conductor of length 2l, what is the ratio of the new resistance to the original resistance?", "explanation": "Volume is conserved: πr²l = πr''²(2l), giving r''² = r²/2. The new resistance R'' = ρ(2l)/(πr²/2) = 4ρl/(πr²) = 4R. Since resistance R = ρl/A, doubling length while conserving volume halves the area, making the new resistance 4 times the original.", "correct_answer": "C", "concept_tags": ["resistance", "reshaping-conductor", "volume-conservation"], "payload": {"question_id": "cuet-phy-current-ohm-19", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 1", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "4 : 1", "is_correct": true}, {"key": "D", "text": "8 : 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would only be true if both length and area remain unchanged. Reshaping changes both dimensions.", "misconception": "Thinking reshaping does not change resistance"}, {"option_key": "B", "hint": "2:1 considers only the length doubling (R ∝ l) but ignores the halving of cross-sectional area due to volume conservation.", "misconception": "Forgetting to account for area change when volume is conserved"}, {"option_key": "D", "hint": "8:1 would apply if length were tripled (R ∝ n²), not doubled. For doubling, R'' = 2² × R = 4R.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A copper wire of cross-sectional area 2 mm² carries a current of 10 A. If the number density of free electrons is 8 × 10²⁸ per m³, the drift velocity of electrons is approximately:", "explanation": "Using I = nAevd, we get vd = I/(nAe) = 10/(8 × 10²⁸ × 2 × 10⁻⁶ × 1.6 × 10⁻¹⁹) = 10/(8 × 2 × 1.6 × 10³) = 10/25600 ≈ 3.9 × 10⁻⁴ m/s ≈ 0.4 mm/s. This demonstrates that despite large current, electron drift velocity is very small.", "correct_answer": "B", "concept_tags": ["drift-velocity", "current", "number-density", "electron-charge"], "payload": {"question_id": "cuet-phy-current-ohm-20", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "3.9 × 10⁻² m/s", "is_correct": false}, {"key": "B", "text": "3.9 × 10⁻⁴ m/s", "is_correct": true}, {"key": "C", "text": "3.9 × 10⁻⁶ m/s", "is_correct": false}, {"key": "D", "text": "3.9 × 10⁻¹ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3.9 × 10⁻² m/s is 100 times too large, likely from an error in unit conversion of the area (using m² instead of mm²).", "misconception": "Forgetting to convert mm² to m²"}, {"option_key": "C", "hint": "3.9 × 10⁻⁶ m/s is 100 times too small, possibly from an extra factor error in the calculation.", "misconception": null}, {"option_key": "D", "hint": "3.9 × 10⁻¹ m/s is unrealistically large for drift velocity in a conductor. Typical drift velocities are of the order 10⁻⁴ m/s.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b01');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Manganin and constantan are preferred for making standard resistors.\nReason (R): These alloys have very low temperature coefficients of resistance.", "explanation": "The assertion is true: manganin and constantan are used for standard resistors and resistance coils. The reason is also true: these alloys have very low temperature coefficients (nearly zero), so their resistance remains practically constant over a wide range of temperatures. The reason correctly explains the assertion, since standard resistors need stable resistance values regardless of temperature changes.", "correct_answer": "A", "concept_tags": ["temperature-coefficient", "alloys", "standard-resistors", "manganin", "constantan"], "payload": {"question_id": "cuet-phy-current-ohm-25", "subtopic": "Temperature Dependence of Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why these alloys are chosen: their low temperature coefficient ensures stable resistance values, which is exactly what standard resistors need.", "misconception": "Not seeing the causal connection between low temperature coefficient and suitability as standard resistors"}, {"option_key": "C", "hint": "The reason is true: manganin has a temperature coefficient of ~0.00001 per °C, which is extremely low compared to metals like copper (~0.004 per °C).", "misconception": "Thinking alloys have high temperature coefficients"}, {"option_key": "D", "hint": "The assertion is true: manganin and constantan are indeed the standard materials used for precision resistance coils in laboratories.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The resistance of a metallic conductor increases with increase in temperature.\nReason (R): With increase in temperature, the average relaxation time of free electrons in the conductor decreases.", "explanation": "Both the assertion and reason are correct. When temperature increases, lattice ions vibrate more vigorously, leading to more frequent collisions with free electrons. This decreases the relaxation time (τ). Since R = ml/(ne²τA), a decrease in τ directly causes an increase in resistance. Thus R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["temperature-dependence", "resistance", "relaxation-time", "metallic-conductor"], "payload": {"question_id": "cuet-phy-current-ohm-26", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The decrease in relaxation time directly explains the increase in resistance through R ∝ 1/τ, so R is indeed the correct explanation of A.", "misconception": "Failing to see the direct causal link between relaxation time and resistance"}, {"option_key": "C", "hint": "The reason is correct: increased lattice vibrations at higher temperatures do decrease the average relaxation time.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct: metals have a positive temperature coefficient of resistance, so their resistance increases with temperature.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When resistors are connected in series, the equivalent resistance is always greater than the largest individual resistance.\nReason (R): In a series circuit, the current through each resistor is different.", "explanation": "The assertion is true: in a series combination, R_eq = R₁ + R₂ + ... which is always greater than any individual resistance. The reason is false: in a series circuit, the same current flows through each resistor (not different currents). Different currents occur in parallel circuits. Since the reason is false, the correct answer is that A is true but R is false.", "correct_answer": "C", "concept_tags": ["series-combination", "equivalent-resistance", "current", "misconception"], "payload": {"question_id": "cuet-phy-current-ohm-27", "subtopic": "Series and Parallel Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": true}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason states that current through each resistor is different in series. This is incorrect; in a series circuit, the same current flows through every component.", "misconception": "Confusing series and parallel circuit current properties"}, {"option_key": "B", "hint": "Since the reason itself is factually wrong (current is the same in series, not different), both cannot be true.", "misconception": null}, {"option_key": "D", "hint": "The assertion is definitely true: R_eq = R₁ + R₂ + ... is always greater than any single R_i when all are positive.", "misconception": "Doubting that series equivalent exceeds individual values"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Resistivity of a semiconductor decreases with increase in temperature.\nReason (R): The number density of charge carriers in a semiconductor increases exponentially with temperature.", "explanation": "Both the assertion and reason are correct. In semiconductors, increasing temperature provides thermal energy that breaks covalent bonds, creating more electron-hole pairs. The number of charge carriers increases exponentially with temperature (n ∝ e^(-Eg/2kT)). Since ρ = 1/(neμ), the massive increase in n more than compensates for any decrease in mobility, causing resistivity to decrease. The reason correctly explains the assertion.", "correct_answer": "A", "concept_tags": ["semiconductor", "resistivity", "temperature-dependence", "charge-carriers"], "payload": {"question_id": "cuet-phy-current-ohm-28", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The increase in charge carriers is the primary reason for decreased resistivity in semiconductors, so R directly explains A.", "misconception": "Not recognizing that carrier concentration is the dominant factor controlling semiconductor resistivity"}, {"option_key": "C", "hint": "The reason is correct: carrier concentration in semiconductors follows n ∝ e^(-Eg/2kT), which is an exponential increase with temperature.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct: semiconductors have a negative temperature coefficient of resistance, meaning resistivity decreases as temperature rises.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following physical quantities (Column-I) with their SI units (Column-II):\n\nColumn-I:\nA. Resistivity\nB. Conductivity\nC. Current density\nD. Mobility\n\nColumn-II:\n1. A/m²\n2. m²/(V·s)\n3. Ω·m\n4. S/m", "explanation": "Resistivity (ρ) has SI unit Ω·m (A→3). Conductivity (σ = 1/ρ) has SI unit S/m or Ω⁻¹m⁻¹ (B→4). Current density (J = I/A) has SI unit A/m² (C→1). Mobility (μ = vd/E) has SI unit m²/(V·s) (D→2). Each quantity''s unit follows directly from its defining equation.", "correct_answer": "B", "concept_tags": ["SI-units", "resistivity", "conductivity", "current-density", "mobility"], "payload": {"question_id": "cuet-phy-current-ohm-29", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the units of conductivity (S/m) and current density (A/m²). Conductivity is B→4 (S/m), not B→1.", "misconception": "Confusing units of conductivity and current density"}, {"option_key": "C", "hint": "This assigns Ω·m to conductivity and S/m to resistivity, which reverses them. Resistivity is Ω·m and conductivity is S/m.", "misconception": "Swapping resistivity and conductivity units"}, {"option_key": "D", "hint": "This completely scrambles all matchings. For instance, resistivity has units Ω·m (3), not A/m² (1).", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following materials (Column-I) with their typical resistivity range at room temperature (Column-II):\n\nColumn-I:\nA. Copper (metal)\nB. Germanium (semiconductor)\nC. Glass (insulator)\nD. Nichrome (alloy)\n\nColumn-II:\n1. ~10¹⁰ – 10¹⁴ Ω·m\n2. ~10⁻⁸ Ω·m\n3. ~10⁻⁶ Ω·m\n4. ~0.1 – 1 Ω·m", "explanation": "Copper is a good metal with very low resistivity ~10⁻⁸ Ω·m (A→2). Germanium is a semiconductor with moderate resistivity ~0.1–1 Ω·m (B→4). Glass is an insulator with very high resistivity ~10¹⁰–10¹⁴ Ω·m (C→1). Nichrome is a resistive alloy with resistivity ~10⁻⁶ Ω·m (D→3). The range spans over 22 orders of magnitude from metals to insulators.", "correct_answer": "C", "concept_tags": ["resistivity", "metals", "semiconductors", "insulators", "alloys"], "payload": {"question_id": "cuet-phy-current-ohm-30", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-2, B-3, C-1, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "C", "text": "A-2, B-4, C-1, D-3", "is_correct": true}, {"key": "D", "text": "A-2, B-1, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Germanium and Nichrome. Germanium (~0.1–1 Ω·m) has much higher resistivity than Nichrome (~10⁻⁶ Ω·m).", "misconception": "Thinking alloys have higher resistivity than semiconductors"}, {"option_key": "B", "hint": "This assigns ~10⁻⁶ Ω·m to copper and ~10⁻⁸ Ω·m to nichrome. Copper has lower resistivity than nichrome alloy.", "misconception": "Confusing resistivity of pure metals with alloys"}, {"option_key": "D", "hint": "This assigns insulator-range resistivity to germanium and semiconductor-range to glass, which is reversed.", "misconception": "Confusing semiconductor and insulator resistivity ranges"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The drift velocity of electrons is directly proportional to the applied electric field across the conductor.", "explanation": "This statement is TRUE. The drift velocity v_d = eEτ/m, where E is the electric field, e is the electron charge, τ is the relaxation time, and m is the electron mass. Since e, τ, and m are constants for a given conductor at constant temperature, v_d is directly proportional to E. The proportionality constant μ = eτ/m is called the mobility.", "correct_answer": "A", "concept_tags": ["drift-velocity", "electric-field", "mobility", "proportionality"], "payload": {"question_id": "cuet-phy-current-ohm-31", "subtopic": "Drift Velocity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The relation v_d = (eτ/m)E = μE clearly shows direct proportionality between drift velocity and electric field.", "misconception": "Thinking drift velocity is independent of or inversely proportional to electric field"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Ohm''s law is valid only when the physical conditions such as temperature remain constant.", "explanation": "This statement is TRUE. Ohm''s law (V = IR with constant R) holds only when physical conditions like temperature, pressure, and mechanical strain remain constant. If temperature changes, the resistance of the conductor changes, and the V-I relationship may no longer be linear.", "correct_answer": "A", "concept_tags": ["ohms-law", "validity", "temperature", "physical-conditions"], "payload": {"question_id": "cuet-phy-current-ohm-32", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Ohm''s law is not universally valid under all conditions. It requires constant physical conditions, especially temperature, to hold.", "misconception": "Thinking Ohm''s law is universally valid regardless of conditions"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The resistance of a superconductor below its critical temperature is very high but finite.", "explanation": "This statement is FALSE. A superconductor below its critical temperature has exactly zero resistance, not a very high resistance. This is the defining property of superconductivity: the electrical resistance drops abruptly to zero below the critical temperature, allowing current to flow without any energy dissipation.", "correct_answer": "B", "concept_tags": ["superconductor", "resistance", "critical-temperature"], "payload": {"question_id": "cuet-phy-current-ohm-33", "subtopic": "Temperature Dependence of Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A superconductor has zero resistance (not high resistance) below the critical temperature. This is the fundamental property of superconductivity.", "misconception": "Confusing superconductor properties with insulator properties"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The resistivity of a material depends on its dimensions (length and cross-sectional area).", "explanation": "This statement is FALSE. Resistivity (ρ) is an intrinsic property of the material and does not depend on the dimensions of the conductor. It depends on the nature of the material and temperature. Resistance (R = ρl/A) depends on dimensions, but resistivity itself is independent of length and area.", "correct_answer": "B", "concept_tags": ["resistivity", "intrinsic-property", "dimensions"], "payload": {"question_id": "cuet-phy-current-ohm-34", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Resistivity is a material property that does not change with the dimensions of the conductor. Only resistance depends on length and area.", "misconception": "Confusing resistance (depends on dimensions) with resistivity (intrinsic material property)"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The mobility of charge carriers is defined as the drift velocity per unit ________.", "explanation": "Mobility μ = v_d / E, where v_d is the drift velocity and E is the electric field. Therefore, mobility is defined as the drift velocity per unit electric field. Its SI unit is m²V⁻¹s⁻¹. Mobility is a measure of how quickly charge carriers can move through a material under the influence of an electric field.", "correct_answer": "D", "concept_tags": ["mobility", "drift-velocity", "electric-field"], "payload": {"question_id": "cuet-phy-current-ohm-35", "subtopic": "Mobility", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "remember", "options": [{"key": "A", "text": "potential difference", "is_correct": false}, {"key": "B", "text": "current", "is_correct": false}, {"key": "C", "text": "resistance", "is_correct": false}, {"key": "D", "text": "electric field", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Potential difference (voltage) is not the same as electric field. Mobility is specifically defined as v_d/E, drift velocity per unit electric field.", "misconception": "Confusing potential difference with electric field"}, {"option_key": "B", "hint": "Mobility has no direct relation to current in its definition. It is defined as μ = v_d/E.", "misconception": "Confusing mobility with conductance-related quantities"}, {"option_key": "C", "hint": "Resistance is a bulk property of a conductor, not the quantity that appears in the definition of mobility.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The relation between current I, number density of electrons n, charge of electron e, cross-sectional area A, and drift velocity vd is I = _____.", "explanation": "The current in a conductor is given by I = neAvd, where n is the number density of free electrons, e is the electronic charge, A is the cross-sectional area, and vd is the drift velocity. This relation is derived by calculating the total charge crossing a cross-section per unit time.", "correct_answer": "C", "concept_tags": ["drift-velocity", "current", "number-density", "cross-section"], "payload": {"question_id": "cuet-phy-current-ohm-36", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "neA/vd", "is_correct": false}, {"key": "B", "text": "nevd/A", "is_correct": false}, {"key": "C", "text": "neAvd", "is_correct": true}, {"key": "D", "text": "ne/(Avd)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Dividing by vd would mean increasing drift velocity decreases current, which contradicts the fact that faster drift produces more current.", "misconception": "Inverting the relationship between drift velocity and current"}, {"option_key": "B", "hint": "Dividing by A would mean a thinner wire carries more current for the same drift velocity, which is incorrect.", "misconception": "Incorrectly placing area in the denominator"}, {"option_key": "D", "hint": "This expression has both A and vd in the denominator, which would incorrectly suggest current decreases with both area and drift velocity.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A physics student measures the V-I characteristics of a device and obtains the following data: at V = 2 V, I = 20 mA; at V = 4 V, I = 40 mA; at V = 6 V, I = 80 mA; at V = 8 V, I = 160 mA. The student claims the device obeys Ohm''s law throughout the entire range.\n\nWhich of the following is the correct conclusion?", "explanation": "For an ohmic device, V/I must remain constant. For V = 2V: R = 100 Ω; V = 4V: R = 100 Ω; V = 6V: R = 75 Ω; V = 8V: R = 50 Ω. The resistance is constant only up to 4V, after which it decreases. Therefore, the device obeys Ohm''s law only up to 4V and is non-ohmic beyond that.", "correct_answer": "D", "concept_tags": ["ohms-law", "V-I-characteristics", "ohmic-device", "non-ohmic"], "payload": {"question_id": "cuet-phy-current-ohm-37", "subtopic": "Ohm''s Law and Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "The device obeys Ohm''s law throughout the range", "is_correct": false}, {"key": "B", "text": "The device does not obey Ohm''s law at any point", "is_correct": false}, {"key": "C", "text": "The device is ohmic only above 4 V", "is_correct": false}, {"key": "D", "text": "The device is ohmic only up to 4 V and non-ohmic beyond that", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "At 6 V and 8 V, the V/I ratio changes (R decreases from 100 Ω to 75 Ω and 50 Ω), so the device does not obey Ohm''s law throughout.", "misconception": "Not checking whether V/I remains constant across all data points"}, {"option_key": "B", "hint": "At 2 V and 4 V, V/I = 100 Ω in both cases, showing linear behaviour and Ohm''s law compliance in that range.", "misconception": null}, {"option_key": "C", "hint": "Above 4 V, the current increases faster than voltage (V/I decreases), which is non-ohmic behaviour, not ohmic.", "misconception": "Confusing ohmic and non-ohmic regions"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "Based on the scenario described, the final equivalent resistance of the entire combination is:", "explanation": "Step 1: P = 6 Ω ∥ 12 Ω = (6×12)/(6+12) = 72/18 = 4 Ω. Step 2: Q = P + 2 Ω = 4 + 2 = 6 Ω (series). Step 3: Series combination of 4 Ω and 8 Ω = 4 + 8 = 12 Ω. Step 4: Final = Q ∥ 12 Ω = (6 × 12)/(6 + 12) = 72/18 = 4 Ω.", "correct_answer": "B", "concept_tags": ["series-parallel", "equivalent-resistance", "problem-solving"], "payload": {"question_id": "cuet-phy-current-ohm-38", "subtopic": "Series and Parallel Resistors", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "analyze", "options": [{"key": "A", "text": "6 Ω", "is_correct": false}, {"key": "B", "text": "4 Ω", "is_correct": true}, {"key": "C", "text": "3 Ω", "is_correct": false}, {"key": "D", "text": "8 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 Ω is the intermediate result Q (after step 2). The final step requires finding Q in parallel with the 4+8=12 Ω series combination.", "misconception": "Stopping the calculation at an intermediate step"}, {"option_key": "C", "hint": "3 Ω does not result from any correct combination of the steps described. Recheck: Q = 6 Ω, series = 12 Ω, parallel = 4 Ω.", "misconception": null}, {"option_key": "D", "hint": "8 Ω is one of the individual resistor values. The systematic series-parallel reduction gives 4 Ω.", "misconception": "Confusing an individual resistor value with the final equivalent"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order to derive the expression for drift velocity of electrons in a conductor using the free electron model:", "explanation": "The derivation begins by (2) considering free electrons in a conductor under electric field E. Then (1) applying F = eE and Newton''s law gives acceleration a = eE/m. Next (4) we introduce the concept of relaxation time τ as the average time between collisions. Then (5) using v_d = aτ connects drift velocity to the acceleration and relaxation time. Finally (3) substituting a = eE/m gives the result v_d = eEτ/m.", "correct_answer": "A", "concept_tags": ["drift-velocity", "free-electron-model", "derivation", "relaxation-time"], "payload": {"question_id": "cuet-phy-current-ohm-39", "subtopic": "Drift Velocity", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "understand", "options": [{"key": "A", "text": "2 → 1 → 4 → 5 → 3", "is_correct": true}, {"key": "B", "text": "1 → 2 → 3 → 4 → 5", "is_correct": false}, {"key": "C", "text": "2 → 4 → 1 → 3 → 5", "is_correct": false}, {"key": "D", "text": "4 → 2 → 5 → 1 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "You cannot apply Newton''s law (step 1) before setting up the physical scenario (step 2). The derivation must begin with the model setup.", "misconception": "Not following the logical structure of a physics derivation"}, {"option_key": "C", "hint": "Step 1 (finding acceleration) must come before step 5 (using v_d = aτ), since step 5 requires the expression for acceleration.", "misconception": "Skipping the acceleration step before using it"}, {"option_key": "D", "hint": "Starting with relaxation time (step 4) before establishing the physical setup and force analysis is not logically correct.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-ohm", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "A student wants to determine the unknown resistance of a wire using a metre bridge (based on Wheatstone bridge principle). Arrange the following experimental steps in the correct sequence:", "explanation": "The correct experimental sequence is: (5) First check all connections and ensure the circuit is properly set up. (1) Then connect the standard resistance and unknown resistance in the appropriate gaps. (2) Close the key and find the null point by moving the jockey along the wire. (3) Note the balancing length and calculate the unknown resistance. (4) Repeat for different standard resistance values and take the mean for accuracy.", "correct_answer": "D", "concept_tags": ["metre-bridge", "wheatstone-bridge", "experiment", "resistance-measurement"], "payload": {"question_id": "cuet-phy-current-ohm-40", "subtopic": "Resistance", "topic_name": "Ohm''s Law and Resistance", "bloom_level": "apply", "options": [{"key": "A", "text": "1 → 5 → 2 → 3 → 4", "is_correct": false}, {"key": "B", "text": "5 → 1 → 3 → 2 → 4", "is_correct": false}, {"key": "C", "text": "1 → 2 → 5 → 4 → 3", "is_correct": false}, {"key": "D", "text": "5 → 1 → 2 → 3 → 4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Checking connections (step 5) must be done before connecting resistances (step 1), not after. Safety and setup verification always come first.", "misconception": "Skipping preliminary checks in an experiment"}, {"option_key": "B", "hint": "You cannot calculate the unknown resistance (step 3) before finding the null point (step 2). The balancing length is determined experimentally first.", "misconception": "Attempting calculation before taking measurements"}, {"option_key": "C", "hint": "Checking connections (step 5) after finding the null point makes no sense. Also, repetition (step 4) should come after calculation (step 3).", "misconception": "Disorganized experimental procedure"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Kirchhoff''s voltage law (KVL), when we traverse a closed loop in a circuit, the algebraic sum of all the EMFs and potential drops equals:", "explanation": "Kirchhoff''s voltage law states that the algebraic sum of all the potential differences (including EMFs and IR drops) around any closed loop in a circuit is zero. This is a direct consequence of the conservation of energy — a charge that travels around a complete loop must return to the same potential it started at.", "correct_answer": "B", "concept_tags": ["kirchhoff-loop-rule", "KVL", "conservation-of-energy", "potential-difference"], "payload": {"question_id": "cuet-phy-current-kirchhoff-01", "subtopic": "Kirchhoff''s loop/voltage rule (KVL)", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "remember", "options": [{"key": "A", "text": "The total EMF of the circuit", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "The total resistance of the loop", "is_correct": false}, {"key": "D", "text": "The total current in the loop", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "KVL does not equate the sum to the total EMF; it accounts for both EMFs and voltage drops together summing to zero.", "misconception": "Thinking KVL separates EMFs from drops as an equation"}, {"option_key": "C", "hint": "Resistance is not a potential difference. KVL deals with voltages, not resistances.", "misconception": "Confusing resistance with voltage"}, {"option_key": "D", "hint": "Current is measured in amperes, while KVL deals with potential differences measured in volts.", "misconception": "Mixing up current and voltage quantities"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "While applying the sign convention in Kirchhoff''s loop rule, if we traverse a resistor in the direction opposite to the assumed current flow, the potential change across it is:", "explanation": "When traversing a resistor opposite to the direction of current, we move from a lower potential to a higher potential. Current flows from high to low potential through a resistor, so going against the current means we encounter a rise in potential, i.e., +IR.", "correct_answer": "A", "concept_tags": ["sign-convention", "KVL", "potential-drop", "resistor"], "payload": {"question_id": "cuet-phy-current-kirchhoff-02", "subtopic": "Sign conventions", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "understand", "options": [{"key": "A", "text": "+IR (a rise in potential)", "is_correct": true}, {"key": "B", "text": "−IR (a drop in potential)", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "+IR² (proportional to power)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A drop (−IR) occurs when you traverse the resistor in the same direction as the current, not opposite.", "misconception": "Reversing the sign convention for traversal direction"}, {"option_key": "C", "hint": "The potential change across a current-carrying resistor is never zero (unless R = 0 or I = 0).", "misconception": "Assuming no voltage drop across a resistor"}, {"option_key": "D", "hint": "IR² is not even dimensionally correct for voltage. The potential change is IR, not IR².", "misconception": "Confusing power dissipation formula with voltage drop"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Kirchhoff''s junction rule is based on the conservation of:", "explanation": "Kirchhoff''s junction rule (or current rule) states that the algebraic sum of currents at any junction is zero (ΣI = 0). This means the total current entering a junction equals the total current leaving it, which is a direct consequence of conservation of electric charge.", "correct_answer": "A", "concept_tags": ["kirchhoff-junction-rule", "conservation-of-charge", "current"], "payload": {"question_id": "cuet-phy-current-kirchhoff-03", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "remember", "options": [{"key": "A", "text": "Charge", "is_correct": true}, {"key": "B", "text": "Energy", "is_correct": false}, {"key": "C", "text": "Momentum", "is_correct": false}, {"key": "D", "text": "Mass", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Conservation of energy is the basis of Kirchhoff''s loop rule (voltage rule), not the junction rule.", "misconception": "Confusing the physical basis of the junction rule with the loop rule"}, {"option_key": "C", "hint": "Conservation of momentum applies to mechanics (collisions, etc.), not to current flow at a junction.", "misconception": null}, {"option_key": "D", "hint": "Conservation of mass is relevant in chemical reactions and fluid flow, not in the context of electrical current at a junction.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Three resistors of 2 Ω, 3 Ω, and 6 Ω are connected in parallel. The equivalent resistance of the combination is:", "explanation": "For parallel resistors: 1/Req = 1/2 + 1/3 + 1/6 = 3/6 + 2/6 + 1/6 = 6/6 = 1. Therefore Req = 1 Ω. The equivalent resistance of a parallel combination is always less than the smallest individual resistance.", "correct_answer": "B", "concept_tags": ["parallel-combination", "equivalent-resistance"], "payload": {"question_id": "cuet-phy-current-kirchhoff-04", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "remember", "options": [{"key": "A", "text": "11 Ω", "is_correct": false}, {"key": "B", "text": "1 Ω", "is_correct": true}, {"key": "C", "text": "3.67 Ω", "is_correct": false}, {"key": "D", "text": "0.5 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "11 Ω = 2 + 3 + 6 would be the result if the resistors were connected in series, not parallel.", "misconception": "Using series formula instead of parallel formula"}, {"option_key": "C", "hint": "3.67 Ω is the arithmetic mean of the three resistances, which is not how equivalent resistance is calculated.", "misconception": null}, {"option_key": "D", "hint": "The equivalent resistance of this parallel combination is 1 Ω, not 0.5 Ω. Check the calculation: 1/2 + 1/3 + 1/6 = 1.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b01');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The terminal voltage of a cell is less than its EMF when it is:", "explanation": "When a cell supplies current (discharging), the terminal voltage V = E - Ir, where E is the EMF, I is the current, and r is the internal resistance. Due to the voltage drop Ir across the internal resistance, the terminal voltage is always less than the EMF during discharge.", "correct_answer": "C", "concept_tags": ["EMF", "terminal-voltage", "internal-resistance", "discharging"], "payload": {"question_id": "cuet-phy-current-kirchhoff-05", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "remember", "options": [{"key": "A", "text": "In open circuit", "is_correct": false}, {"key": "B", "text": "Being charged by an external source", "is_correct": false}, {"key": "C", "text": "Supplying current to an external resistance", "is_correct": true}, {"key": "D", "text": "Not connected to any circuit", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "In open circuit, no current flows (I = 0), so V = E - 0 = E. The terminal voltage equals the EMF.", "misconception": "Thinking terminal voltage differs from EMF even in open circuit"}, {"option_key": "B", "hint": "During charging, V = E + Ir, so the terminal voltage is actually greater than the EMF, not less.", "misconception": "Confusing charging and discharging conditions"}, {"option_key": "D", "hint": "When not connected to any circuit, it is the same as open circuit where V = E (no current flows).", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Kirchhoff''s loop rule (voltage rule) states that the algebraic sum of potential differences in a closed loop is:", "explanation": "Kirchhoff''s loop rule states that the algebraic sum of all potential differences (voltage drops and rises) around any closed loop in a circuit is zero (ΣV = 0). This is based on the conservation of energy: the energy gained per unit charge by EMF sources equals the energy lost per unit charge across resistances in a complete loop.", "correct_answer": "D", "concept_tags": ["kirchhoff-loop-rule", "conservation-of-energy", "potential-difference"], "payload": {"question_id": "cuet-phy-current-kirchhoff-06", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "remember", "options": [{"key": "A", "text": "Equal to the total EMF in the circuit", "is_correct": false}, {"key": "B", "text": "Equal to the total resistance", "is_correct": false}, {"key": "C", "text": "Maximum at the junction", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The loop rule states ΣV = 0 around a closed loop, meaning all EMFs and IR drops together sum to zero, not that the sum equals the total EMF.", "misconception": "Confusing the loop equation with one side of the equation"}, {"option_key": "B", "hint": "The loop rule deals with voltages (potential differences), not resistances. Total resistance is not a quantity that potential differences sum to.", "misconception": null}, {"option_key": "C", "hint": "The loop rule applies around a complete closed loop, not at a junction. The junction rule deals with currents at a node.", "misconception": "Confusing the loop rule with the junction rule"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a circuit, three branches meet at a node. Branch 1 carries 4 A into the node, Branch 2 carries 1.5 A out of the node, and Branch 3 carries current I₃. Using Kirchhoff''s current law, the value of I₃ is:", "explanation": "By KCL, the sum of currents entering a node equals the sum of currents leaving it. Current in = 4 A. Current out = 1.5 A + I₃. Therefore 4 = 1.5 + I₃, giving I₃ = 2.5 A flowing out of the node.", "correct_answer": "C", "concept_tags": ["KCL", "junction-rule", "current-conservation", "node-analysis"], "payload": {"question_id": "cuet-phy-current-kirchhoff-07", "subtopic": "Kirchhoff''s junction/current rule (KCL)", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "5.5 A flowing out of the node", "is_correct": false}, {"key": "B", "text": "2.5 A flowing into the node", "is_correct": false}, {"key": "C", "text": "2.5 A flowing out of the node", "is_correct": true}, {"key": "D", "text": "4.0 A flowing out of the node", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "5.5 A would be the sum of 4 + 1.5, which ignores the direction convention. KCL requires current in = current out.", "misconception": "Adding all currents without regard to direction"}, {"option_key": "B", "hint": "If I₃ also flows into the node, the total inflow would be 6.5 A but only 1.5 A leaves — violating charge conservation.", "misconception": "Incorrect direction assignment for the unknown current"}, {"option_key": "D", "hint": "4 A is the incoming current from Branch 1. The outgoing current in Branch 3 must balance the difference, not equal the incoming.", "misconception": "Assuming each outgoing branch carries the full incoming current"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two cells of EMF 3 V and 5 V with internal resistances 1 Ω and 2 Ω respectively are connected in parallel (positive to positive) across an external resistance of 10 Ω. The current through the external resistance is approximately:", "explanation": "For two cells in parallel with EMFs E₁ = 3 V (r₁ = 1 Ω) and E₂ = 5 V (r₂ = 2 Ω), the equivalent EMF is E_eq = (E₁/r₁ + E₂/r₂)/(1/r₁ + 1/r₂) = (3/1 + 5/2)/(1/1 + 1/2) = (3 + 2.5)/(1 + 0.5) = 5.5/1.5 = 11/3 V. The equivalent internal resistance is r_eq = 1/(1/r₁ + 1/r₂) = 1/(1 + 0.5) = 2/3 Ω. Current through external resistance = E_eq/(r_eq + R) = (11/3)/(2/3 + 10) = (11/3)/(32/3) = 11/32 ≈ 0.34 A.", "correct_answer": "D", "concept_tags": ["cells-in-parallel", "equivalent-EMF", "internal-resistance", "KVL"], "payload": {"question_id": "cuet-phy-current-kirchhoff-08", "subtopic": "Grouping of cells (series/parallel/mixed)", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "0.50 A", "is_correct": false}, {"key": "B", "text": "0.67 A", "is_correct": false}, {"key": "C", "text": "0.25 A", "is_correct": false}, {"key": "D", "text": "0.34 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.50 A would result if you used a simple average EMF of 4 V divided by a wrong total resistance. The parallel EMF formula must be used.", "misconception": "Averaging EMFs instead of using the weighted formula"}, {"option_key": "B", "hint": "0.67 A is 2/3, which is the equivalent internal resistance value, not the current.", "misconception": "Confusing intermediate calculation values with the final answer"}, {"option_key": "C", "hint": "0.25 A underestimates the current. Check whether the equivalent EMF and resistance were computed correctly.", "misconception": "Using incorrect formula for parallel combination of unequal cells"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a Wheatstone bridge circuit with resistances P = 100 Ω, Q = 200 Ω, R = 150 Ω, and S = 300 Ω, the bridge is:", "explanation": "For a balanced Wheatstone bridge, the condition is P/Q = R/S. Here P/Q = 100/200 = 1/2 and R/S = 150/300 = 1/2. Since P/Q = R/S, the bridge is balanced and no current flows through the galvanometer.", "correct_answer": "A", "concept_tags": ["wheatstone-bridge", "balanced-bridge", "KCL", "KVL"], "payload": {"question_id": "cuet-phy-current-kirchhoff-09", "subtopic": "Multi-loop circuit analysis", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "Balanced, with zero current through the galvanometer", "is_correct": true}, {"key": "B", "text": "Unbalanced, with current flowing from B to D", "is_correct": false}, {"key": "C", "text": "Unbalanced, with current flowing from D to B", "is_correct": false}, {"key": "D", "text": "Balanced only if the battery EMF exceeds 2 V", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Check the balance condition P/Q vs R/S. If they are equal, the bridge is balanced regardless of current direction arguments.", "misconception": "Incorrectly evaluating the balance condition ratios"}, {"option_key": "C", "hint": "This would be true only if P/Q ≠ R/S. Verify the ratios numerically before concluding the bridge is unbalanced.", "misconception": "Arithmetic error in ratio comparison"}, {"option_key": "D", "hint": "The balance condition depends only on the resistance ratios, not on the EMF of the battery.", "misconception": "Thinking bridge balance depends on EMF value"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a mixed grouping of cells, m rows of n cells each (EMF = E, internal resistance = r) are connected across an external resistance R. The current through R is maximum when:", "explanation": "For a mixed grouping, the total EMF = nE and total internal resistance = nr/m. The current I = nE/(nr/m + R) = mnE/(nr + mR). By AM-GM inequality, the current is maximized when the internal resistance equals the external resistance, i.e., nr/m = R, which gives R = nr/m.", "correct_answer": "B", "concept_tags": ["mixed-grouping", "maximum-current", "internal-resistance", "cells"], "payload": {"question_id": "cuet-phy-current-kirchhoff-10", "subtopic": "Grouping of cells (series/parallel/mixed)", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "analyze", "options": [{"key": "A", "text": "R = mr/n", "is_correct": false}, {"key": "B", "text": "R = nr/m", "is_correct": true}, {"key": "C", "text": "R = mnr", "is_correct": false}, {"key": "D", "text": "R = r/(mn)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps m and n. In each row of n cells in series, the internal resistance is nr. With m rows in parallel, the net internal resistance is nr/m, not mr/n.", "misconception": "Confusing the role of m (rows) and n (cells per row)"}, {"option_key": "C", "hint": "mnr would be the total internal resistance if all cells were in series. Mixed grouping uses parallel rows to reduce internal resistance.", "misconception": "Treating all cells as if connected in series"}, {"option_key": "D", "hint": "r/(mn) is far too small and would only apply if all cells somehow combined their resistances in parallel without any series connection.", "misconception": "Incorrect application of series-parallel resistance formula"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cell of EMF 2 V and internal resistance 0.5 Ω is connected to an external resistance of 1.5 Ω. The current in the circuit and the terminal voltage of the cell are:", "explanation": "Total resistance = R + r = 1.5 + 0.5 = 2 Ω. Current I = E/(R + r) = 2/2 = 1 A. Terminal voltage V = E - Ir = 2 - 1(0.5) = 1.5 V. Alternatively, V = IR = 1 × 1.5 = 1.5 V. The terminal voltage is less than the EMF due to internal resistance drop.", "correct_answer": "C", "concept_tags": ["EMF", "internal-resistance", "terminal-voltage", "current"], "payload": {"question_id": "cuet-phy-current-kirchhoff-11", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "I = 2 A, V = 1 V", "is_correct": false}, {"key": "B", "text": "I = 1 A, V = 2 V", "is_correct": false}, {"key": "C", "text": "I = 1 A, V = 1.5 V", "is_correct": true}, {"key": "D", "text": "I = 0.5 A, V = 1.75 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I = 2 A would result from using only internal resistance (I = E/r = 2/0.5 = 4) or another error. The correct total resistance is 2 Ω giving I = 1 A.", "misconception": "Forgetting to include both internal and external resistance in total resistance"}, {"option_key": "B", "hint": "V = 2 V would mean the terminal voltage equals the EMF, which only occurs in open circuit (I = 0). With I = 1 A, V = E - Ir = 1.5 V.", "misconception": "Ignoring the voltage drop across internal resistance"}, {"option_key": "D", "hint": "I = 0.5 A would require a total resistance of 4 Ω, but R + r = 1.5 + 0.5 = 2 Ω. The correct current is 1 A.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two resistors of 4 Ω and 12 Ω are connected in parallel, and this combination is connected in series with a 3 Ω resistor. The total equivalent resistance is:", "explanation": "Parallel combination of 4 Ω and 12 Ω: 1/Rp = 1/4 + 1/12 = 3/12 + 1/12 = 4/12, so Rp = 3 Ω. This is in series with 3 Ω, so total Req = 3 + 3 = 6 Ω. In series combinations, resistances add directly.", "correct_answer": "B", "concept_tags": ["series-parallel", "equivalent-resistance", "combination-circuits"], "payload": {"question_id": "cuet-phy-current-kirchhoff-12", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "3 Ω", "is_correct": false}, {"key": "B", "text": "6 Ω", "is_correct": true}, {"key": "C", "text": "19 Ω", "is_correct": false}, {"key": "D", "text": "9 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 Ω is only the equivalent of the parallel combination (4 Ω ∥ 12 Ω). You must add the series 3 Ω resistor to get the total.", "misconception": "Forgetting to add the series resistance to the parallel combination"}, {"option_key": "C", "hint": "19 Ω = 4 + 12 + 3 would be the result of adding all three resistors in series, ignoring the parallel connection.", "misconception": "Treating all resistors as being in series"}, {"option_key": "D", "hint": "9 Ω does not match any correct combination. The parallel equivalent is 3 Ω, and adding 3 Ω in series gives 6 Ω.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When n identical cells each of EMF E and internal resistance r are connected in series, the total EMF and total internal resistance of the combination are:", "explanation": "When n identical cells are connected in series, the EMFs add up and the internal resistances also add up. Total EMF = nE and total internal resistance = nr. This is because in series, the same current flows through each cell and the potential differences across them add up.", "correct_answer": "A", "concept_tags": ["cells-in-series", "EMF", "internal-resistance", "grouping-of-cells"], "payload": {"question_id": "cuet-phy-current-kirchhoff-13", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "understand", "options": [{"key": "A", "text": "nE, nr", "is_correct": true}, {"key": "B", "text": "nE, r/n", "is_correct": false}, {"key": "C", "text": "E, nr", "is_correct": false}, {"key": "D", "text": "E, r/n", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "r/n is the total internal resistance for parallel connection, not series. In series, internal resistances add to give nr.", "misconception": "Mixing up series and parallel formulas for internal resistance"}, {"option_key": "C", "hint": "Total EMF in series is nE, not E. The EMF remains E only in parallel connection of identical cells.", "misconception": "Confusing series grouping with parallel grouping of cells"}, {"option_key": "D", "hint": "This gives the result for parallel combination (EMF = E, internal resistance = r/n), not series.", "misconception": "Applying parallel cell formulas to series connection"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a circuit, five currents I₁ = 3 A, I₂ = 5 A, I₃ = 2 A flow into a junction, while I₄ = 4 A flows out. By Kirchhoff''s junction rule, the fifth current I₅ flowing out of the junction is:", "explanation": "By Kirchhoff''s junction rule, the sum of currents entering a junction equals the sum of currents leaving it. Currents in: 3 + 5 + 2 = 10 A. Currents out: 4 + I₅. Therefore, 10 = 4 + I₅, giving I₅ = 6 A flowing out of the junction.", "correct_answer": "D", "concept_tags": ["kirchhoff-junction-rule", "current-conservation", "node-analysis"], "payload": {"question_id": "cuet-phy-current-kirchhoff-14", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "2 A", "is_correct": false}, {"key": "B", "text": "4 A", "is_correct": false}, {"key": "C", "text": "10 A", "is_correct": false}, {"key": "D", "text": "6 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2 A does not satisfy the junction rule. Total current in = 10 A, total current out must also be 10 A: 4 + I₅ = 10, so I₅ = 6 A.", "misconception": null}, {"option_key": "B", "hint": "4 A flowing out would give total outgoing current = 4 + 4 = 8 A, which does not equal the incoming 10 A.", "misconception": null}, {"option_key": "C", "hint": "10 A is the total current flowing into the junction, not the unknown outgoing current. I₅ = 10 - 4 = 6 A.", "misconception": "Confusing total incoming current with the unknown outgoing current"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cell of EMF 1.5 V and internal resistance 1 Ω supplies maximum power to an external resistance R. The value of R is:", "explanation": "Maximum power is transferred to the external resistance when R equals the internal resistance of the source, i.e., R = r. This is the maximum power transfer theorem. Here r = 1 Ω, so R = 1 Ω for maximum power transfer. At this condition, the efficiency is 50%.", "correct_answer": "B", "concept_tags": ["maximum-power-transfer", "internal-resistance", "external-resistance"], "payload": {"question_id": "cuet-phy-current-kirchhoff-15", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 Ω", "is_correct": false}, {"key": "B", "text": "1 Ω", "is_correct": true}, {"key": "C", "text": "1.5 Ω", "is_correct": false}, {"key": "D", "text": "3 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "For maximum power transfer, R must equal r (not r/2). With R = 0.5 Ω, the power to R is not maximized.", "misconception": null}, {"option_key": "C", "hint": "1.5 V is the EMF, not the required external resistance. For max power, R = r = 1 Ω.", "misconception": "Confusing the EMF value with the required resistance"}, {"option_key": "D", "hint": "R = 3 Ω is three times the internal resistance. Maximum power transfer requires R = r = 1 Ω, not R = 3r.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When n identical cells each of EMF E and internal resistance r are connected in parallel across an external resistance R, the current through R is:", "explanation": "When n identical cells are connected in parallel, the effective EMF remains E (same as one cell) and the effective internal resistance becomes r/n. The current through the external resistance R is I = E/(R + r/n) = nE/(nR + r). This arrangement is useful when internal resistance is much larger than external resistance.", "correct_answer": "C", "concept_tags": ["cells-in-parallel", "EMF", "internal-resistance", "current"], "payload": {"question_id": "cuet-phy-current-kirchhoff-16", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "nE/(R + nr)", "is_correct": false}, {"key": "B", "text": "E/(R + nr)", "is_correct": false}, {"key": "C", "text": "nE/(nR + r)", "is_correct": true}, {"key": "D", "text": "nE/(R + r)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "nE/(R + nr) corresponds to n cells in series (EMF = nE, internal resistance = nr), not parallel.", "misconception": "Applying series cell formula instead of parallel"}, {"option_key": "B", "hint": "E/(R + nr) incorrectly adds internal resistances in series while keeping single cell EMF, which is not any standard configuration.", "misconception": null}, {"option_key": "D", "hint": "nE/(R + r) does not correctly account for the reduction in internal resistance. In parallel, internal resistance becomes r/n.", "misconception": "Not reducing the internal resistance correctly for parallel cells"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a circuit, a 10 V battery with internal resistance 1 Ω is connected to three resistors: R₁ = 4 Ω in series with a parallel combination of R₂ = 6 Ω and R₃ = 3 Ω. Using Kirchhoff''s laws, the current drawn from the battery is:", "explanation": "The parallel combination of R₂ and R₃: R_parallel = (6 × 3)/(6 + 3) = 18/9 = 2 Ω. Total resistance in the circuit = internal resistance + R₁ + R_parallel = 1 + 4 + 2 = 7 Ω. Current from battery = EMF / total resistance = 10/7 ≈ 1.43 A.", "correct_answer": "C", "concept_tags": ["series-parallel", "KVL", "internal-resistance", "circuit-analysis"], "payload": {"question_id": "cuet-phy-current-kirchhoff-17", "subtopic": "Multi-loop circuit analysis", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "apply", "options": [{"key": "A", "text": "2.00 A", "is_correct": false}, {"key": "B", "text": "1.00 A", "is_correct": false}, {"key": "C", "text": "10/7 A ≈ 1.43 A", "is_correct": true}, {"key": "D", "text": "10/11 A ≈ 0.91 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2 A would mean the total resistance is 5 Ω, which ignores the parallel combination and simply adds R₂ or R₃ individually.", "misconception": "Using only one of the parallel resistors instead of computing the combination"}, {"option_key": "B", "hint": "1 A implies a total resistance of 10 Ω. This would occur if R₂ and R₃ were in series (9 Ω) instead of parallel (2 Ω).", "misconception": "Treating parallel resistors as series"}, {"option_key": "D", "hint": "10/11 A arises from adding all resistances in series: 1 + 4 + 6 = 11 Ω, which treats R₂ and R₃ as series and ignores R₃ = 3 Ω or vice versa.", "misconception": "Adding wrong combination of resistors"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A network consists of 12 identical resistors each of resistance R, forming the edges of a cube. The equivalent resistance between two diagonally opposite corners of the cube is:", "explanation": "By symmetry arguments and applying Kirchhoff''s laws to the cube network: current entering one corner splits equally among 3 edges, then at the next level splits again. Using the symmetry of the cube, the equivalent resistance between diagonally opposite corners is 5R/6. This is a classic result derived by noting that due to symmetry, certain nodes are at the same potential and can be short-circuited without affecting the circuit.", "correct_answer": "D", "concept_tags": ["symmetry", "cube-network", "equivalent-resistance", "KCL", "KVL"], "payload": {"question_id": "cuet-phy-current-kirchhoff-18", "subtopic": "Symmetry in circuits", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "analyze", "options": [{"key": "A", "text": "R", "is_correct": false}, {"key": "B", "text": "3R/4", "is_correct": false}, {"key": "C", "text": "7R/12", "is_correct": false}, {"key": "D", "text": "5R/6", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R would be the resistance of a single edge. The network of 12 resistors cannot simplify to just one resistor.", "misconception": "Oversimplifying the cube network"}, {"option_key": "B", "hint": "3R/4 is the equivalent resistance between adjacent corners of the cube, not diagonally opposite corners.", "misconception": "Confusing diagonal corners with adjacent corners"}, {"option_key": "C", "hint": "7R/12 is the equivalent resistance between the midpoints of opposite edges or between corners along a face diagonal, not the body diagonal.", "misconception": "Using the wrong pair of nodes for the cube resistance formula"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In the circuit shown, two cells of EMF E₁ = 6 V (r₁ = 1 Ω) and E₂ = 4 V (r₂ = 1 Ω) are connected in opposition (opposing polarities) across an external resistance of 8 Ω. The current in the circuit is:", "explanation": "When two cells are connected in opposition, the effective EMF is the difference of the two EMFs: E_eff = E₁ - E₂ = 6 - 4 = 2 V. The internal resistances add up (since current passes through both): total internal resistance = r₁ + r₂ = 1 + 1 = 2 Ω. Current I = E_eff/(R + r₁ + r₂) = 2/(8 + 2) = 0.2 A.", "correct_answer": "A", "concept_tags": ["cells-in-opposition", "EMF", "internal-resistance", "current"], "payload": {"question_id": "cuet-phy-current-kirchhoff-19", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "analyze", "options": [{"key": "A", "text": "0.2 A", "is_correct": true}, {"key": "B", "text": "1 A", "is_correct": false}, {"key": "C", "text": "0.5 A", "is_correct": false}, {"key": "D", "text": "2 A", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1 A would result from using E₁ + E₂ = 10 V in series aiding (I = 10/10 = 1 A), but the cells are in opposition so E_eff = 2 V.", "misconception": "Adding EMFs instead of subtracting for cells in opposition"}, {"option_key": "C", "hint": "0.5 A would result from using E_eff = 2 V but forgetting one internal resistance: I = 2/(3+1) = 0.5, which is incorrect.", "misconception": null}, {"option_key": "D", "hint": "2 A would result from ignoring the external resistance entirely: I = 2/1 = 2 A, which is incorrect.", "misconception": "Forgetting to include the external resistance"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A 12 V battery with internal resistance 2 Ω is connected across a combination where a 6 Ω and a 3 Ω resistor are in parallel, and this parallel combination is in series with a 4 Ω resistor. The current drawn from the battery is:", "explanation": "Parallel combination: 1/Rp = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2, so Rp = 2 Ω. Total external resistance = 2 + 4 = 6 Ω. Total resistance including internal = 6 + 2 = 8 Ω. Current I = 12/8 = 1.5 A.", "correct_answer": "B", "concept_tags": ["series-parallel", "internal-resistance", "battery", "circuit-analysis"], "payload": {"question_id": "cuet-phy-current-kirchhoff-20", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 A", "is_correct": false}, {"key": "B", "text": "1.5 A", "is_correct": true}, {"key": "C", "text": "2 A", "is_correct": false}, {"key": "D", "text": "3 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 A would require total resistance of 12 Ω. The total resistance is 8 Ω (2 Ω parallel + 4 Ω series + 2 Ω internal).", "misconception": null}, {"option_key": "C", "hint": "2 A would result from ignoring the internal resistance: I = 12/6 = 2 A. The internal resistance must be included.", "misconception": "Forgetting to include internal resistance of the battery"}, {"option_key": "D", "hint": "3 A would result from ignoring both the series resistor and internal resistance, using only the parallel combination.", "misconception": "Ignoring series elements in the circuit"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In applying Kirchhoff''s loop rule, the sign of the potential change across a battery depends on the direction of traversal relative to the battery, not on the direction of current through the battery.\n\nReason (R): A battery is a source of constant EMF, and the potential always rises from the negative terminal to the positive terminal inside the battery, regardless of the current direction.", "explanation": "The Assertion is true: when traversing from − to + terminal of a battery, we write +E regardless of current direction. The Reason is also true and correctly explains the Assertion. A battery maintains a fixed polarity, so the sign convention for EMF in KVL depends only on traversal direction relative to the battery terminals. Thus both A and R are true, and R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["sign-convention", "KVL", "EMF", "battery-polarity"], "payload": {"question_id": "cuet-phy-current-kirchhoff-25", "subtopic": "Sign conventions", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly addresses why the sign convention for a battery in KVL depends on traversal direction — the fixed polarity. So R does explain A.", "misconception": "Failing to see the causal link between fixed polarity and sign convention"}, {"option_key": "C", "hint": "The Reason is factually correct — potential inside a battery does rise from − to + terminal by definition of EMF.", "misconception": "Incorrectly thinking the potential direction inside a battery changes with current direction"}, {"option_key": "D", "hint": "The Assertion is correct. In KVL, the battery''s EMF sign depends on whether you traverse from − to + (gain) or + to − (drop), not on current direction.", "misconception": "Confusing current direction with traversal direction for sign convention"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The equivalent resistance of resistors connected in parallel is always less than the smallest individual resistance.\nReason (R): In a parallel combination, the reciprocal of equivalent resistance equals the sum of reciprocals of individual resistances.", "explanation": "Both statements are correct. For n resistors in parallel, 1/Req = 1/R₁ + 1/R₂ + ... + 1/Rn. Since each term on the right is positive, 1/Req > 1/Ri for any individual resistor Ri, which means Req < Ri. The mathematical relationship in R directly leads to and explains the physical fact stated in A.", "correct_answer": "A", "concept_tags": ["parallel-combination", "equivalent-resistance", "mathematical-proof"], "payload": {"question_id": "cuet-phy-current-kirchhoff-26", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reciprocal formula (R) directly proves why Req is always less than each Ri (A). Since 1/Req > 1/Ri for every i, R provides the mathematical explanation for A.", "misconception": "Not recognizing the direct causal connection between the formula and the property"}, {"option_key": "C", "hint": "The reason is the correct formula for parallel resistance: 1/Req = Σ(1/Ri). This is a standard result.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. For example, 2 Ω ∥ 3 Ω = 6/5 = 1.2 Ω, which is less than 2 Ω (the smallest).", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In a circuit with two cells of different EMFs connected in parallel across an external resistance, the cell with the higher EMF will have a current flowing through it in the direction opposite to its EMF (it gets charged).\n\nReason (R): When cells of unequal EMF are connected in parallel, the cell with higher EMF acts as a source and the cell with lower EMF may act as a load (current flows into its positive terminal), depending on the circuit parameters.", "explanation": "The Assertion is false. The cell with the higher EMF acts as a source (discharges), supplying current in the conventional direction from its positive terminal through the external circuit. It is the cell with the lower EMF that may get charged if the potential difference across the parallel combination exceeds its EMF. The Reason is true — it correctly states that the higher EMF cell acts as a source and the lower one may act as a load. Since A is false, the correct option is D.", "correct_answer": "D", "concept_tags": ["cells-in-parallel", "unequal-EMF", "charging-cell", "KVL"], "payload": {"question_id": "cuet-phy-current-kirchhoff-27", "subtopic": "Internal resistance of cells", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Read the Assertion carefully: it says the higher EMF cell gets charged. This contradicts the Reason which says the higher EMF cell acts as a source.", "misconception": "Not noticing the contradiction between A and R"}, {"option_key": "B", "hint": "If A were true, the higher EMF cell would be getting charged — but that is physically incorrect. The higher EMF cell discharges.", "misconception": "Accepting the Assertion without critical analysis"}, {"option_key": "C", "hint": "The Assertion claims the higher EMF cell gets charged. In reality, a higher EMF cell drives current through the circuit and discharges, so A is false.", "misconception": "Confusing which cell charges and which discharges in a parallel combination"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-kirchhoff", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When identical cells are connected in parallel, the arrangement is preferred when the external resistance is much smaller than the internal resistance.\nReason (R): Connecting cells in parallel increases the total EMF of the combination.", "explanation": "The assertion is correct. For parallel cells (effective EMF = E, internal resistance = r/n), current I = E/(R + r/n). When R << r, parallel connection gives I ≈ nE/r, which is n times the current from a single cell. However, the reason is incorrect: connecting identical cells in parallel does not increase the EMF; it remains E. The total EMF stays the same as one cell; only the internal resistance is reduced.", "correct_answer": "C", "concept_tags": ["cells-in-parallel", "EMF", "internal-resistance", "preferred-connection"], "payload": {"question_id": "cuet-phy-current-kirchhoff-28", "subtopic": "Kirchhoff''s Laws and Networks", "topic_name": "Kirchhoff''s Laws and Circuit Analysis", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason is factually incorrect. Parallel connection of identical cells does NOT increase total EMF; it remains E. Only series connection increases EMF to nE.", "misconception": "Believing parallel cells increase EMF"}, {"option_key": "B", "hint": "The reason is incorrect (EMF does not increase in parallel), so option B, which states both are correct, cannot be right.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct: parallel grouping is preferred when R << r, as it maximizes current by reducing effective internal resistance to r/n.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b01');

